// AWS Cloud Practitioner (CLF-C02) - 150 Questions
const CCP_QUESTIONS = [
{id:'ccp1',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the primary benefit of cloud computing over traditional on-premises infrastructure?',options:['Guaranteed 100% uptime','Trade fixed expenses for variable expenses','Eliminates the need for IT staff','Provides free storage'],correct:1,explanation:'Cloud computing lets you pay only for what you use (variable expenses) rather than investing in data centers upfront (fixed expenses). This is a core advantage of cloud adoption.'},
{id:'ccp2',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'Which AWS support plan provides a Technical Account Manager (TAM)?',options:['Developer','Business','Enterprise On-Ramp','Enterprise'],correct:3,explanation:'The Enterprise support plan includes a dedicated Technical Account Manager (TAM) who provides proactive guidance and advocacy.'},
{id:'ccp3',exams:['ccp','saa'],domain:'Cloud Concepts',difficulty:'easy',text:'What does the AWS Shared Responsibility Model state about customer responsibility?',options:['AWS manages everything','Customers are responsible for security IN the cloud','Customers are responsible for security OF the cloud','AWS handles patching of all customer EC2 instances'],correct:1,explanation:'Customers are responsible for security IN the cloud (data, OS, apps), while AWS handles security OF the cloud (physical infrastructure, hypervisor).'},
{id:'ccp4',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:"Which of the following best describes 'elasticity' in cloud computing?",options:['The ability to move workloads between cloud providers','The ability to scale resources up or down automatically based on demand','The durability of stored data','The geographic distribution of data centers'],correct:1,explanation:'Elasticity is the ability to automatically acquire resources as needed and release them when no longer required.'},
{id:'ccp5',exams:['ccp','saa'],domain:'Cloud Concepts',difficulty:'easy',text:'What is an AWS Region?',options:['A single data center','A collection of Availability Zones in a geographic area','An edge location for caching content','A logical grouping of AWS accounts'],correct:1,explanation:'An AWS Region is a physical location containing multiple isolated Availability Zones within a geographic area.'},
{id:'ccp6',exams:['ccp','saa','dva'],domain:'Security & Compliance',difficulty:'easy',text:'Which AWS service provides a managed firewall to protect web applications from common exploits?',options:['AWS Shield','AWS WAF','Amazon GuardDuty','AWS Firewall Manager'],correct:1,explanation:'AWS WAF (Web Application Firewall) protects web applications from common exploits like SQL injection and XSS.'},
{id:'ccp7',exams:['ccp','saa','dva'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS IAM used for?',options:['Monitoring application performance','Managing user access and permissions to AWS services','Encrypting data at rest','Providing DDoS protection'],correct:1,explanation:'AWS IAM manages access to AWS services and resources securely through users, groups, roles, and policies.'},
{id:'ccp8',exams:['ccp','saa'],domain:'Security & Compliance',difficulty:'easy',text:'Which AWS service helps detect threats by continuously monitoring your AWS accounts?',options:['AWS Inspector','Amazon Macie','Amazon GuardDuty','AWS Config'],correct:2,explanation:'Amazon GuardDuty is a threat detection service that continuously monitors for malicious activity and unauthorized behavior.'},
{id:'ccp9',exams:['ccp','saa','dva'],domain:'Security & Compliance',difficulty:'easy',text:'What is the principle of least privilege?',options:['Users should have the most permissions possible','Granting only the minimum permissions needed to perform a task','All users share the same permissions','Admins have unlimited access'],correct:1,explanation:'Least privilege means giving users, apps, and systems only the permissions they need and nothing more.'},
{id:'ccp10',exams:['ccp','saa'],domain:'Security & Compliance',difficulty:'easy',text:'Which service provides hardware-based key storage for regulatory compliance?',options:['AWS KMS','AWS CloudHSM','AWS Secrets Manager','AWS Certificate Manager'],correct:1,explanation:'AWS CloudHSM provides dedicated hardware security modules (HSMs) for cryptographic key storage meeting strict compliance requirements.'},
{id:'ccp11',exams:['ccp','dva'],domain:'Technology',difficulty:'easy',text:'Which AWS compute service runs code without provisioning or managing servers?',options:['Amazon EC2','Amazon ECS','AWS Lambda','Amazon Lightsail'],correct:2,explanation:'AWS Lambda is a serverless compute service that runs code in response to events without provisioning servers.'},
{id:'ccp12',exams:['ccp','saa','dva'],domain:'Technology',difficulty:'easy',text:'What is Amazon S3 primarily used for?',options:['Running virtual machines','Object storage','Relational database hosting','Content delivery'],correct:1,explanation:'Amazon S3 is an object storage service offering scalability, durability, and performance for storing any amount of data.'},
{id:'ccp13',exams:['ccp','saa','dva'],domain:'Technology',difficulty:'easy',text:'Which AWS service is a fully managed relational database service?',options:['Amazon DynamoDB','Amazon Redshift','Amazon RDS','Amazon ElastiCache'],correct:2,explanation:'Amazon RDS makes it easy to set up, operate, and scale relational databases including MySQL, PostgreSQL, Oracle, and SQL Server.'},
{id:'ccp14',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'What is Amazon CloudFront?',options:['A DNS service','A content delivery network (CDN)','A virtual private cloud','A monitoring service'],correct:1,explanation:'Amazon CloudFront is a CDN that securely delivers data, videos, applications, and APIs globally with low latency.'},
{id:'ccp15',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'Which service enables running containerized applications on AWS without managing servers?',options:['Amazon ECS on EC2','AWS Fargate','Amazon EC2 Auto Scaling','AWS Elastic Beanstalk'],correct:1,explanation:'AWS Fargate is a serverless compute engine for containers, removing the need to provision and manage servers.'},
{id:'ccp16',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'What does Amazon VPC allow you to do?',options:['Monitor application metrics','Launch AWS resources in an isolated virtual network','Manage DNS records','Cache frequently accessed data'],correct:1,explanation:'Amazon VPC lets you provision a logically isolated section of AWS Cloud where you launch resources in a virtual network you define.'},
{id:'ccp17',exams:['ccp','saa','dva'],domain:'Technology',difficulty:'easy',text:'Which AWS service provides a fully managed NoSQL database?',options:['Amazon RDS','Amazon Aurora','Amazon DynamoDB','Amazon Redshift'],correct:2,explanation:'Amazon DynamoDB is a fully managed, serverless key-value NoSQL database with single-digit millisecond performance.'},
{id:'ccp18',exams:['ccp','dva'],domain:'Technology',difficulty:'easy',text:'What is AWS Elastic Beanstalk?',options:['A container orchestration service','A PaaS that automatically handles deployment, capacity, and scaling','A serverless function service','A managed Kubernetes service'],correct:1,explanation:'AWS Elastic Beanstalk automatically handles deployment, capacity provisioning, load balancing, auto-scaling, and health monitoring.'},
{id:'ccp19',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is the AWS Free Tier?',options:['A support plan for free','Services that are always free for all customers','A program offering free usage of certain services for new AWS customers','Free training and certification'],correct:2,explanation:'The AWS Free Tier lets new customers explore AWS services free of charge, including Always Free, 12 Months Free, and short-term trials.'},
{id:'ccp20',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'Which pricing model offers the largest discount for EC2 instances in exchange for a commitment?',options:['On-Demand','Spot Instances','Reserved Instances','Dedicated Hosts'],correct:2,explanation:'Reserved Instances offer up to 72% discount over On-Demand pricing in exchange for a 1 or 3-year commitment.'},
{id:'ccp21',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is AWS Cost Explorer used for?',options:['Monitoring security threats','Visualizing and analyzing AWS costs and usage over time','Managing IAM permissions','Setting up billing alerts'],correct:1,explanation:'AWS Cost Explorer lets you visualize, understand, and manage your AWS costs and usage with intuitive graphs and filtering.'},
{id:'ccp22',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'Which AWS tool helps estimate costs before deploying resources?',options:['AWS Cost Explorer','AWS Budgets','AWS Pricing Calculator','AWS Trusted Advisor'],correct:2,explanation:'The AWS Pricing Calculator allows you to estimate the cost of AWS services for your use case before deploying anything.'},
{id:'ccp23',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What are Spot Instances?',options:['Reserved capacity for a specific AZ','Unused EC2 capacity available at steep discounts with possible interruption','Instances dedicated to a single customer','On-demand instances with enhanced networking'],correct:1,explanation:'Spot Instances use spare EC2 capacity at up to 90% off On-Demand prices. AWS can reclaim them with a 2-minute warning.'},
{id:'ccp24',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'Which of the following is an example of horizontal scaling?',options:['Upgrading an EC2 instance to a larger type','Adding more EC2 instances to handle increased load','Increasing RAM on an existing server','Upgrading the CPU on a database server'],correct:1,explanation:'Horizontal scaling (scale out) adds more instances to distribute load. Vertical scaling (scale up) upgrades existing resources.'},
{id:'ccp25',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS Artifact?',options:['A CI/CD pipeline service','A compliance and audit reports portal','A container registry','An infrastructure-as-code tool'],correct:1,explanation:'AWS Artifact is a self-service portal for on-demand access to AWS compliance reports like SOC, ISO certifications, and PCI.'},
{id:'ccp26',exams:['ccp','saa','dva'],domain:'Technology',difficulty:'easy',text:'Which service automates infrastructure deployment using code?',options:['AWS CodeDeploy','AWS CloudFormation','AWS CodePipeline','AWS CodeBuild'],correct:1,explanation:'AWS CloudFormation lets you model and provision AWS resources by treating infrastructure as code using JSON or YAML templates.'},
{id:'ccp27',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'What is Amazon Route 53?',options:['A managed Kubernetes service','A scalable DNS and domain registration service','A dedicated connection to AWS','A caching service'],correct:1,explanation:'Amazon Route 53 is a highly available and scalable DNS web service that routes requests to internet applications.'},
{id:'ccp28',exams:['ccp','saa','dva'],domain:'Security & Compliance',difficulty:'easy',text:'Which AWS service monitors and records API calls made on your account?',options:['Amazon CloudWatch','AWS CloudTrail','AWS Config','Amazon Inspector'],correct:1,explanation:'AWS CloudTrail records API calls in your AWS account, providing history for security analysis, resource tracking, and compliance auditing.'},
{id:'ccp29',exams:['ccp','dva'],domain:'Technology',difficulty:'easy',text:'What does Amazon SQS provide?',options:['Real-time video streaming','A fully managed message queuing service','A push notification service','A DNS service'],correct:1,explanation:'Amazon SQS is a fully managed message queuing service for decoupling and scaling microservices and distributed systems.'},
{id:'ccp30',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What are the six pillars of the AWS Well-Architected Framework?',options:['Security, Reliability, Performance, Cost, Sustainability, Simplicity','Operational Excellence, Security, Reliability, Performance Efficiency, Cost Optimization, Sustainability','Speed, Security, Scalability, Storage, Serverless, Support','Availability, Security, Monitoring, Optimization, Compliance, Cost'],correct:1,explanation:'The six pillars are: Operational Excellence, Security, Reliability, Performance Efficiency, Cost Optimization, and Sustainability.'},
{id:'ccp31',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'Which AWS service provides a managed Kubernetes service?',options:['Amazon ECS','AWS Fargate','Amazon EKS','AWS Batch'],correct:2,explanation:'Amazon EKS is a fully managed Kubernetes service that makes it easy to deploy, manage, and scale containerized applications.'},
{id:'ccp32',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is Consolidated Billing in AWS Organizations?',options:['Separates billing by department','Combines usage and billing across multiple accounts for potential volume discounts','A detailed line-item invoice for EC2 only','A monthly report sent by email'],correct:1,explanation:'Consolidated Billing lets you consolidate payment for multiple AWS accounts and potentially benefit from combined usage pricing.'},
{id:'ccp33',exams:['ccp','saa'],domain:'Security & Compliance',difficulty:'easy',text:'What is Amazon Inspector used for?',options:['Monitoring cost anomalies','Automated security vulnerability assessment of EC2 and container images','Detecting unusual network activity','Managing SSL certificates'],correct:1,explanation:'Amazon Inspector is an automated vulnerability management service scanning EC2 instances and container images for vulnerabilities.'},
{id:'ccp34',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the definition of high availability?',options:['A system that never goes down','A system designed to minimize downtime and remain operational despite failures','A system with 100% SLA guarantee','Deploying resources across all regions'],correct:1,explanation:'High availability means systems designed to operate continuously with minimal downtime through redundancy and automatic failover.'},
{id:'ccp35',exams:['ccp','saa'],domain:'Security & Compliance',difficulty:'easy',text:'Which AWS service helps protect against DDoS attacks automatically at no extra cost?',options:['AWS WAF','AWS Shield Standard','AWS Firewall Manager','Amazon GuardDuty'],correct:1,explanation:'AWS Shield Standard is automatically included with all accounts at no extra cost, protecting against common DDoS attacks.'},
{id:'ccp36',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'What is AWS Direct Connect?',options:['A VPN service','A dedicated private network connection from on-premises to AWS','A CDN service','A DNS routing policy'],correct:1,explanation:'AWS Direct Connect provides a dedicated private connection between your on-premises network and AWS, bypassing the public internet.'},
{id:'ccp37',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'Which S3 storage class is designed for infrequently accessed data requiring rapid retrieval?',options:['S3 Standard','S3 Glacier','S3 Standard-IA','S3 One Zone-IA'],correct:2,explanation:'S3 Standard-IA is designed for data accessed less frequently but requiring rapid access. Lower storage cost but with a retrieval fee.'},
{id:'ccp38',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What does AWS Budgets allow you to do?',options:['Automatically reduce costs when overspending','Set custom cost and usage budgets and receive alerts when thresholds are exceeded','Pay your AWS bill automatically','Forecast future costs only'],correct:1,explanation:'AWS Budgets lets you set custom cost and usage budgets and receive alerts via email or SNS when thresholds are breached.'},
{id:'ccp39',exams:['ccp','saa'],domain:'Cloud Concepts',difficulty:'easy',text:'What is an AWS Availability Zone?',options:['A geographic region where AWS operates','One or more discrete data centers with redundant power, networking, and connectivity','A content delivery point','A logical grouping of services'],correct:1,explanation:'An AZ consists of one or more discrete data centers with redundant power and networking, providing isolation from failures.'},
{id:'ccp40',exams:['ccp','dva'],domain:'Technology',difficulty:'easy',text:'Which service combination enables serverless APIs?',options:['Amazon EC2','Amazon API Gateway + AWS Lambda','AWS Elastic Beanstalk','Amazon ECS'],correct:1,explanation:'API Gateway handles request routing and management while Lambda executes your code in response to HTTP requests, enabling serverless APIs.'},
{id:'ccp41',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is the purpose of AWS Trusted Advisor?',options:['Providing 24/7 human technical support','Offering real-time guidance following AWS best practices across cost, security, fault tolerance, performance, and service limits','Managing IAM users','Monitoring CloudTrail logs'],correct:1,explanation:'AWS Trusted Advisor provides recommendations across five categories: cost optimization, performance, security, fault tolerance, and service quotas.'},
{id:'ccp42',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'What is Amazon Redshift?',options:['A messaging service','A fully managed data warehouse service','A NoSQL database','A caching solution'],correct:1,explanation:'Amazon Redshift is a fully managed, petabyte-scale data warehouse optimized for analytical (OLAP) workloads.'},
{id:'ccp43',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'Which cloud deployment model keeps all infrastructure on-premises?',options:['Public cloud','Hybrid cloud','Private cloud','Community cloud'],correct:2,explanation:'A private cloud keeps all infrastructure on-premises, giving the organization full control without shared public infrastructure.'},
{id:'ccp44',exams:['ccp','saa','dva'],domain:'Technology',difficulty:'easy',text:'What is Amazon ElastiCache used for?',options:['Storing large files','In-memory caching for low-latency data access','Running containerized workloads','Managing DNS records'],correct:1,explanation:'Amazon ElastiCache provides fully managed in-memory caching (Redis and Memcached) to improve application performance.'},
{id:'ccp45',exams:['ccp','saa','dva'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS Config?',options:['A configuration file management service','Continuously monitors and records AWS resource configurations and evaluates compliance','A tool for setting up IAM policies','A cost anomaly detection service'],correct:1,explanation:'AWS Config continuously monitors and records AWS resource configurations, evaluating them against desired configurations for compliance.'},
{id:'ccp46',exams:['ccp','dva'],domain:'Technology',difficulty:'easy',text:'What is Amazon SNS?',options:['A queue-based messaging service','A fully managed pub/sub messaging service for notifications and fan-out','A streaming data service','An email marketing platform'],correct:1,explanation:'Amazon SNS is a fully managed pub/sub messaging service that enables decoupling of microservices through topics and push notifications.'},
{id:'ccp47',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is a Savings Plan in AWS?',options:['A retirement account offered by AWS','A flexible pricing model offering lower prices for a consistent usage commitment','A way to save your billing preferences','An automatic discount for enterprise customers'],correct:1,explanation:'AWS Savings Plans offer up to 72% savings on EC2, Lambda, and Fargate usage in exchange for a 1 or 3-year usage commitment.'},
{id:'ccp48',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:"What is the concept of 'fault tolerance'?",options:['The ability to process faults quickly','The ability of a system to continue operating even when components fail','The amount of time a system is expected to function','The geographic redundancy of cloud regions'],correct:1,explanation:'Fault tolerance is the ability of a system to remain operational when components fail, through redundancy and automatic failover.'},
{id:'ccp49',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'Which AWS service provides global edge locations to reduce latency?',options:['AWS Direct Connect','Amazon CloudFront','Amazon Route 53','AWS Global Accelerator'],correct:3,explanation:'AWS Global Accelerator uses the AWS global network to route traffic to optimal endpoints, improving availability and performance.'},
{id:'ccp50',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is a hybrid cloud deployment?',options:['Deploying all workloads to public cloud','Connecting on-premises infrastructure with cloud resources','Using multiple public cloud providers','A private data center with cloud-like management'],correct:1,explanation:'A hybrid cloud connects on-premises infrastructure with cloud resources, allowing workloads to run in the most appropriate environment.'},
{id:'ccp51',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'Which service provides a managed Apache Kafka offering on AWS?',options:['Amazon SQS','Amazon SNS','Amazon MSK','Amazon Kinesis'],correct:2,explanation:'Amazon MSK (Managed Streaming for Apache Kafka) is a fully managed service for Apache Kafka to process streaming data.'},
{id:'ccp52',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'What is Amazon Aurora?',options:['A NoSQL database','A MySQL/PostgreSQL-compatible relational database with up to 5x performance','A data warehouse','An in-memory cache'],correct:1,explanation:'Amazon Aurora is a MySQL and PostgreSQL-compatible relational database that is up to 5x faster, with automated backups and multi-AZ replication.'},
{id:'ccp53',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is Amazon Macie?',options:['A DDoS protection service','A fully managed data security service using ML to discover and protect sensitive data in S3','An intrusion detection system','A key management service'],correct:1,explanation:'Amazon Macie uses machine learning to automatically discover, classify, and protect sensitive data stored in Amazon S3.'},
{id:'ccp54',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What does "pay-as-you-go" pricing mean in AWS?',options:['You pay upfront for a year of usage','You only pay for the resources you actually use, when you use them','You get a fixed monthly bill regardless of usage','You pay after a free 6-month trial'],correct:1,explanation:'Pay-as-you-go pricing means you pay only for the compute, storage, and other resources you actually use, with no long-term contracts.'},
{id:'ccp55',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon ECS?',options:['A managed Kubernetes service','A fully managed container orchestration service','A serverless function service','A CI/CD pipeline tool'],correct:1,explanation:'Amazon ECS (Elastic Container Service) is a fully managed container orchestration service for Docker containers.'},
{id:'ccp56',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is the purpose of an Internet Gateway in AWS?',options:['To connect VPCs to each other','To allow communication between a VPC and the internet','To route traffic between Availability Zones','To provide private connectivity to AWS services'],correct:1,explanation:'An Internet Gateway enables communication between instances in your VPC and the internet.'},
{id:'ccp57',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS Security Hub?',options:['A physical security operations center','A service that provides a comprehensive view of security alerts and compliance status across accounts','A VPN management tool','A firewall configuration service'],correct:1,explanation:'AWS Security Hub gives a centralized view of security alerts and compliance status across your AWS accounts and services.'},
{id:'ccp58',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is a Reserved Instance?',options:['An instance that is always running and cannot be stopped','A pricing model offering discounts in exchange for commitment to a specific instance type over 1 or 3 years','An instance reserved for AWS internal use','A dedicated physical server'],correct:1,explanation:'Reserved Instances offer significant discounts (up to 72%) compared to On-Demand in exchange for committing to a specific instance configuration.'},
{id:'ccp59',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is AWS CloudFormation?',options:['A weather monitoring service','An infrastructure as code service for provisioning AWS resources','A code repository service','A monitoring service'],correct:1,explanation:'AWS CloudFormation is an IaC (Infrastructure as Code) service that uses templates to provision and manage AWS resources.'},
{id:'ccp60',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What does Auto Scaling do?',options:['Manually increases server size','Automatically adjusts the number of EC2 instances based on demand','Migrates databases automatically','Manages DNS routing'],correct:1,explanation:'Auto Scaling automatically adjusts the number of EC2 instances in response to demand, ensuring availability and reducing costs.'},
{id:'ccp61',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is a Security Group in AWS?',options:['A team of AWS security specialists','A virtual firewall that controls inbound and outbound traffic for EC2 instances','A group of IAM users with shared permissions','An encryption key group'],correct:1,explanation:'A Security Group acts as a virtual firewall at the instance level, controlling inbound and outbound traffic for EC2 instances.'},
{id:'ccp62',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon EBS?',options:['An email service','Block storage volumes for use with EC2 instances','An elastic load balancer','An object storage service'],correct:1,explanation:'Amazon EBS (Elastic Block Store) provides persistent block storage volumes that attach to EC2 instances, similar to a hard drive.'},
{id:'ccp63',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is the purpose of AWS CloudWatch?',options:['Storing code repositories','Monitoring resources and applications, collecting metrics and logs','Automating software deployments','Managing user identities'],correct:1,explanation:'Amazon CloudWatch monitors AWS resources and applications, collecting metrics, logs, and events to provide operational visibility.'},
{id:'ccp64',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What does "agility" mean in the context of cloud computing?',options:['The speed of physical server delivery','The ability to quickly provision and deprovision resources, reducing time to experiment and deploy','The geographic speed of data transfer','The flexibility to change cloud providers'],correct:1,explanation:'Cloud agility means being able to quickly spin up resources needed for experiments and deploying new applications in minutes.'},
{id:'ccp65',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is Multi-Factor Authentication (MFA) in AWS?',options:['Using multiple AWS accounts','Requiring two or more verification factors to gain access','Having multiple passwords','Using multiple IAM roles simultaneously'],correct:1,explanation:'MFA adds an extra layer of security by requiring users to provide two or more verification factors in addition to their password.'},
{id:'ccp66',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Lightsail?',options:['A lightweight version of EC2','An easy-to-use cloud platform for simple web apps, websites, and small databases with predictable pricing','A low-power IoT device service','A simplified S3 storage tier'],correct:1,explanation:'Amazon Lightsail is designed for simpler use cases like websites and small apps, offering preconfigured VPS with predictable monthly pricing.'},
{id:'ccp67',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is the AWS Cost and Usage Report (CUR)?',options:['A daily email with cost summaries','The most comprehensive set of AWS cost and usage data, including metadata about services and pricing','A simplified one-page bill','An automated cost reduction tool'],correct:1,explanation:'The CUR provides the most detailed data about your AWS costs and usage, including hourly/daily breakdowns with resource-level granularity.'},
{id:'ccp68',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Step Functions?',options:['A manual process documentation tool','A serverless orchestration service for coordinating components of distributed applications','A testing framework for Lambda functions','A CI/CD service'],correct:1,explanation:'AWS Step Functions orchestrates serverless workflows, letting you coordinate Lambda functions and other services into resilient business processes.'},
{id:'ccp69',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the benefit of using multiple Availability Zones?',options:['Lower network latency between servers','Increased fault tolerance and high availability by isolating failures to a single AZ','Reduced AWS pricing','Simplified IAM management'],correct:1,explanation:'Using multiple AZs means a failure in one AZ does not affect your application in other AZs, providing high availability and fault tolerance.'},
{id:'ccp70',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Kinesis Data Streams used for?',options:['Storing video files','Collecting and processing large streams of data records in real time','Queuing messages for async processing','Storing structured relational data'],correct:1,explanation:'Amazon Kinesis Data Streams captures, processes, and stores data streams in real time, enabling real-time analytics and processing.'},
{id:'ccp71',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is the purpose of AWS KMS?',options:['Kubernetes management service','Create and manage cryptographic keys and control their use across AWS services and applications','Key performance monitoring service','A VPN key exchange service'],correct:1,explanation:'AWS KMS (Key Management Service) lets you create and control cryptographic keys used to encrypt your data across AWS services.'},
{id:'ccp72',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon EFS?',options:['A block storage service','An elastic file system that provides scalable shared file storage for EC2 instances','An email filtering service','An edge caching service'],correct:1,explanation:'Amazon EFS (Elastic File System) provides scalable, shared NFS file storage that can be mounted by multiple EC2 instances simultaneously.'},
{id:'ccp73',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is AWS Organizations used for?',options:['Managing employee org charts','Centrally managing multiple AWS accounts, applying policies, and consolidating billing','Organizing S3 buckets into folders','Grouping EC2 instances by team'],correct:1,explanation:'AWS Organizations lets you centrally manage multiple accounts, apply Service Control Policies (SCPs), and consolidate billing across accounts.'},
{id:'ccp74',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is the purpose of an Elastic Load Balancer (ELB)?',options:['Increasing the memory of EC2 instances','Distributing incoming application traffic across multiple targets to increase availability','Elastically sizing storage volumes','Reducing the cost of data transfer'],correct:1,explanation:'ELB automatically distributes incoming traffic across multiple targets (EC2, containers, IPs) improving availability and fault tolerance.'},
{id:'ccp75',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What does "global infrastructure" mean in AWS?',options:['AWS has offices in every country','AWS operates Regions and Availability Zones worldwide to serve customers globally with low latency','AWS provides translation services globally','AWS data is shared across all countries'],correct:1,explanation:"AWS's global infrastructure spans Regions and AZs worldwide, allowing customers to serve end users with low latency wherever they are."},
{id:'ccp76',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is a Network Access Control List (NACL)?',options:['A list of approved IP addresses for SSH access','An optional layer of security acting as a firewall for controlling traffic in and out of subnets','A list of network administrators','An approved list of AWS services you can use'],correct:1,explanation:'NACLs act as a stateless firewall at the subnet level, controlling inbound and outbound traffic with numbered rules.'},
{id:'ccp77',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Glue?',options:['A tool to attach EBS volumes to EC2','A fully managed ETL (extract, transform, load) service for data integration','A service for merging multiple AWS accounts','A code compilation service'],correct:1,explanation:'AWS Glue is a serverless data integration service that makes it easier to discover, prepare, move, and integrate data for analytics.'},
{id:'ccp78',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Athena?',options:['A monitoring dashboard service','An interactive query service to analyze data directly in S3 using SQL','A real-time streaming service','A machine learning training service'],correct:1,explanation:'Amazon Athena lets you run SQL queries directly against data stored in Amazon S3 with no infrastructure to manage, paying per query.'},
{id:'ccp79',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'Which AWS service provides recommendations to reduce costs based on actual usage?',options:['AWS Pricing Calculator','AWS Trusted Advisor','AWS Budgets','AWS Cost Explorer'],correct:1,explanation:'AWS Trusted Advisor analyzes your usage and provides recommendations for cost savings, including identifying idle or underutilized resources.'},
{id:'ccp80',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Comprehend?',options:['A training platform for developers','A natural language processing (NLP) service that finds insights in text','A document storage service','A code comprehension tool'],correct:1,explanation:'Amazon Comprehend uses machine learning to find insights and relationships in unstructured text without requiring ML expertise.'},
{id:'ccp81',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS Secrets Manager?',options:['A service for managing classified government information','Stores, rotates, and retrieves database credentials, API keys, and other secrets','A physical key storage device','An IAM password management tool'],correct:1,explanation:'AWS Secrets Manager helps protect access to applications by securely storing, managing, and rotating secrets like database credentials and API keys.'},
{id:'ccp82',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon SageMaker?',options:['A project management tool','A fully managed service to build, train, and deploy machine learning models at scale','A Kubernetes management service','A streaming media service'],correct:1,explanation:'Amazon SageMaker provides every developer and data scientist with the ability to build, train, and deploy ML models quickly.'},
{id:'ccp83',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is cloud bursting?',options:['When a cloud server crashes under heavy load','A deployment strategy where an application runs in a private cloud but bursts into a public cloud when demand spikes','Exceeding your AWS account limits','A form of data breach'],correct:1,explanation:'Cloud bursting lets applications run in a private cloud but automatically expand into public cloud resources when demand exceeds private capacity.'},
{id:'ccp84',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What does Amazon Rekognition do?',options:['Manages code repositories','Provides image and video analysis using machine learning','Monitors application performance','Recognizes and routes DNS requests'],correct:1,explanation:'Amazon Rekognition is a computer vision service that adds image and video analysis to your applications using deep learning.'},
{id:'ccp85',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is an AWS account root user?',options:['The first IAM user created','The identity created when you first create an AWS account with full access to all services and resources','A special administrator role','An account used for billing only'],correct:1,explanation:'The root user is created when you first set up an AWS account and has unrestricted access. Best practice is to use IAM users for daily tasks.'},
{id:'ccp86',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Polly?',options:['A polling service for surveys','A service that turns text into lifelike speech','A real-time data polling service','A network monitoring tool'],correct:1,explanation:'Amazon Polly uses advanced deep learning to synthesize natural-sounding human speech from text.'},
{id:'ccp87',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS DataSync?',options:['A database synchronization tool','A service that automates and accelerates moving data between on-premises storage and AWS','A real-time data streaming service','A database migration tool'],correct:1,explanation:'AWS DataSync simplifies, automates, and accelerates the transfer of data between on-premises storage systems and AWS storage services.'},
{id:'ccp88',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is Amazon Cognito?',options:['A cognitive computing platform','A service for adding user sign-up, sign-in, and access control to web and mobile apps','A database with cognitive features','An AI-powered security service'],correct:1,explanation:'Amazon Cognito lets you add user authentication and authorization to your web and mobile apps quickly and easily.'},
{id:'ccp89',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS IoT Core?',options:['A service for managing on-premises servers','A managed cloud service for connecting IoT devices securely to the cloud','An internet speed testing service','A core networking component for VPCs'],correct:1,explanation:'AWS IoT Core is a managed service that lets connected devices interact securely with cloud applications and other devices.'},
{id:'ccp90',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the AWS Marketplace?',options:['A physical store for AWS hardware','An online catalog of thousands of software listings from independent software vendors to run on AWS','A job board for AWS professionals','A marketplace for selling unused Reserved Instances'],correct:1,explanation:'AWS Marketplace is a digital catalog of third-party software, data, and services that run on AWS, simplifying procurement and deployment.'},
{id:'ccp91',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Translate?',options:['A document conversion service','A neural machine translation service for fast, high-quality language translation','A DNS translation service','A code language translator'],correct:1,explanation:'Amazon Translate is a neural machine translation service that delivers fast, high-quality, and affordable language translation.'},
{id:'ccp92',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS Control Tower?',options:['A physical control room for AWS operations','A service to set up and govern a secure, multi-account AWS environment following best practices','A network traffic control service','A monitoring dashboard'],correct:1,explanation:'AWS Control Tower automates the set up of a baseline environment (landing zone) for multi-account governance following AWS best practices.'},
{id:'ccp93',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Forecast?',options:['A weather prediction service','A fully managed service using ML to deliver highly accurate time-series forecasts','A financial planning tool','A capacity planning dashboard'],correct:1,explanation:'Amazon Forecast uses machine learning to generate accurate forecasts from time-series data without requiring ML expertise.'},
{id:'ccp94',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is the difference between CapEx and OpEx in cloud computing?',options:['CapEx is cloud costs, OpEx is on-premises costs','CapEx is upfront capital investment (on-premises); OpEx is ongoing operational spend (cloud pay-as-you-go)','There is no difference','CapEx is cheaper than OpEx always'],correct:1,explanation:'Traditional IT uses CapEx (large upfront investment in hardware). Cloud shifts this to OpEx (ongoing operational expenses), improving cash flow.'},
{id:'ccp95',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS CodePipeline?',options:['A visual code editor','A fully managed continuous delivery service for automating release pipelines','A code review tool','A performance testing service'],correct:1,explanation:'AWS CodePipeline is a fully managed CD service that automates your build, test, and deploy phases each time there is a code change.'},
{id:'ccp96',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is a VPN in AWS context?',options:['Virtual Private Network providing encrypted tunnel between on-premises and VPC over the internet','A type of EC2 instance','A Virtual Private Node in a cluster','A billing category'],correct:0,explanation:'An AWS VPN creates an encrypted tunnel between your on-premises network (or client) and your Amazon VPC over the public internet.'},
{id:'ccp97',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Lex?',options:['A legal document service','A service for building conversational interfaces using voice and text (chatbots)','A lexical analysis tool for code','A networking service'],correct:1,explanation:'Amazon Lex is a service for building conversational interfaces using automatic speech recognition and natural language understanding.'},
{id:'ccp98',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the purpose of AWS Personal Health Dashboard?',options:['Monitoring your physical health data','Providing personalized alerts about AWS service events that may affect your resources','Showing the health of your EC2 instances','Displaying your billing health'],correct:1,explanation:'AWS Health Dashboard provides personalized alerts and remediation guidance when AWS is experiencing events that may affect your resources.'},
{id:'ccp99',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Textract?',options:['A text editing service','A service that automatically extracts text, forms, and tables from scanned documents','A text translation service','A content moderation service'],correct:1,explanation:'Amazon Textract uses ML to automatically extract text and data from scanned documents, going beyond simple OCR to identify structure.'},
{id:'ccp100',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is the AWS Snow Family?',options:['A series of winter-themed promotional events','Physical devices for migrating large amounts of data into and out of AWS when internet transfer is impractical','A family of lightweight EC2 instances for cold storage','AWS services for Scandinavian customers'],correct:1,explanation:'The AWS Snow Family (Snowcone, Snowball, Snowmobile) are physical devices used to transfer large amounts of data to AWS when network transfer is too slow or impractical.'},
{id:'ccp101',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS WAF used to protect against?',options:['Physical theft of AWS servers','Common web attacks like SQL injection, cross-site scripting (XSS), and DDoS','Unauthorized AWS account access','Data corruption in S3'],correct:1,explanation:'AWS WAF protects web applications by filtering malicious web traffic, blocking common attack patterns like SQL injection and XSS.'},
{id:'ccp102',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Connect?',options:['A physical networking service','An omnichannel cloud contact center service','A service for connecting VPCs','A partner integration portal'],correct:1,explanation:'Amazon Connect is an easy-to-use omnichannel cloud contact center helping companies provide superior customer service at lower cost.'},
{id:'ccp103',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What does "right-sizing" mean in AWS?',options:['Physically sizing servers correctly','Matching instance types and sizes to actual workload requirements to reduce costs','Sizing your S3 buckets','Standardizing on one instance family'],correct:1,explanation:'Right-sizing means analyzing and selecting the most cost-effective EC2 instance types/sizes that still meet your performance requirements.'},
{id:'ccp104',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the AWS Well-Architected Tool?',options:['A physical measurement tool for data centers','A service that helps review the state of your workloads against AWS best practices','A code quality measurement tool','A project management tool'],correct:1,explanation:'The AWS Well-Architected Tool helps you review your architecture against best practices across the six pillars and provides guidance for improvements.'},
{id:'ccp105',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Batch?',options:['A batch cooking delivery service','A fully managed service for running hundreds of thousands of batch computing jobs on AWS','A bulk S3 file upload tool','A group messaging service'],correct:1,explanation:'AWS Batch dynamically provisions compute resources and schedules batch computing jobs based on volume and resource requirements.'},
{id:'ccp106',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is the AWS Acceptable Use Policy?',options:['A document describing acceptable server room temperatures','A policy describing prohibited uses of AWS services','A guide to acceptable IAM policy syntax','A billing usage agreement'],correct:1,explanation:'The AWS Acceptable Use Policy (AUP) describes prohibited uses of AWS services, including illegal activity, harmful content, and security violations.'},
{id:'ccp107',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Transcribe?',options:['A document scanning service','An automatic speech recognition service that converts audio to text','A text copy service','A language learning platform'],correct:1,explanation:'Amazon Transcribe uses automatic speech recognition (ASR) to convert speech to text, useful for transcribing customer calls and media content.'},
{id:'ccp108',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is an IAM policy?',options:['A physical security policy for data centers','A document that defines permissions and access controls for AWS resources','A billing policy for reserved instances','A network routing policy'],correct:1,explanation:'An IAM policy is a JSON document that defines permissions, specifying which actions are allowed or denied on which AWS resources.'},
{id:'ccp109',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What does AWS X-Ray do?',options:['X-ray scanning of server hardware','Analyzes and debugs distributed applications, providing end-to-end tracing','A penetration testing service','A data visualization tool'],correct:1,explanation:'AWS X-Ray helps developers analyze and debug distributed applications by providing end-to-end view of requests and identifying performance bottlenecks.'},
{id:'ccp110',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is a Dedicated Host?',options:['A hosting plan for dedicated websites','A physical EC2 server fully dedicated to your use, allowing you to bring existing server-bound software licenses','A private S3 bucket','A reserved support engineer'],correct:1,explanation:'A Dedicated Host is a physical server with EC2 instance capacity fully dedicated to your use, useful for regulatory requirements and BYOL licensing.'},
{id:'ccp111',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Timestream?',options:['A video timestamp service','A fast, scalable, fully managed time series database for IoT and operational applications','A calendar service','A scheduling service'],correct:1,explanation:'Amazon Timestream is a purpose-built time series database that makes it easy and cost-effective to store and analyze trillions of time series data points.'},
{id:'ccp112',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is Amazon Detective?',options:['A mystery puzzle game service','A service that analyzes and visualizes security data to help investigate potential security issues','A fraud detection service for e-commerce','A code vulnerability scanner'],correct:1,explanation:'Amazon Detective makes it easy to analyze, investigate, and quickly identify the root cause of potential security issues or suspicious activities.'},
{id:'ccp113',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is a Service Level Agreement (SLA) in AWS?',options:['A signed agreement with your AWS account manager','A commitment by AWS to a specific level of service uptime/performance, with credits if not met','A list of all AWS service features','A support contract'],correct:1,explanation:'An SLA is a formal commitment by AWS about service availability. If the SLA is not met, customers may receive service credits.'},
{id:'ccp114',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS AppSync?',options:['A mobile app synchronization backup service','A managed GraphQL service for building scalable APIs that connect apps to data and services','An app deployment synchronization tool','A calendar sync service'],correct:1,explanation:'AWS AppSync is a managed GraphQL service that simplifies app development by creating a flexible API to securely access, manipulate, and combine data from multiple sources.'},
{id:'ccp115',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Kendra?',options:['A Kenyan customer service portal','An intelligent enterprise search service powered by ML','A key-value database','A container registry'],correct:1,explanation:'Amazon Kendra is an intelligent enterprise search service that uses natural language processing and ML to return accurate search results from your content repositories.'},
{id:'ccp116',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What does AWS Shield Advanced provide beyond Shield Standard?',options:['Nothing - they are identical','24/7 access to the AWS DDoS Response Team, detailed attack diagnostics, and financial protection against scaling charges','Only email alerts for attacks','Protection for on-premises infrastructure only'],correct:1,explanation:'AWS Shield Advanced adds DDoS Response Team support, detailed metrics, attack notifications, and cost protection for scaling charges caused by DDoS attacks.'},
{id:'ccp117',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon DocumentDB?',options:['A physical document archive service','A managed document database service compatible with MongoDB','A service for storing PDF files','A document collaboration tool'],correct:1,explanation:'Amazon DocumentDB is a fully managed MongoDB-compatible document database service, designed for JSON workloads at scale.'},
{id:'ccp118',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the AWS Partner Network (APN)?',options:['A personal networking group for AWS employees','A global community of consulting and technology partners who help customers build on AWS','A peer-to-peer networking protocol for EC2','A referral program for individual users'],correct:1,explanation:'The APN is a global ecosystem of partners—consultants, ISVs, and technology providers—that help customers design, architect, and build on AWS.'},
{id:'ccp119',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Neptune?',options:['A space exploration data service','A fully managed graph database service for building applications with connected data','A deep ocean data analytics service','A high-performance computing cluster'],correct:1,explanation:'Amazon Neptune is a fully managed graph database that supports the Property Graph and RDF models, ideal for social networks, knowledge graphs, and fraud detection.'},
{id:'ccp120',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is the purpose of AWS Cost Anomaly Detection?',options:['Detecting fraudulent AWS accounts','Using ML to continuously monitor costs and alert you to unusual spend patterns','Identifying security anomalies','Detecting performance anomalies'],correct:1,explanation:'AWS Cost Anomaly Detection uses ML to identify unusual spending patterns, sending alerts when costs behave differently from expected norms.'},
{id:'ccp121',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon WorkSpaces?',options:['A coworking space booking service','A managed, persistent cloud desktop (DaaS) solution','A project management tool','A code collaboration environment'],correct:1,explanation:'Amazon WorkSpaces is a fully managed Desktop as a Service (DaaS) solution that gives users access to a cloud desktop from any device.'},
{id:'ccp122',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is the difference between authentication and authorization in IAM?',options:['They are the same thing','Authentication verifies who you are; authorization determines what you are allowed to do','Authentication manages billing; authorization manages networking','Authentication is for humans; authorization is for services'],correct:1,explanation:'Authentication (who are you?) uses credentials to verify identity. Authorization (what can you do?) uses policies to determine allowed actions.'},
{id:'ccp123',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Transit Gateway?',options:['A toll payment gateway for internet traffic','A service that connects VPCs and on-premises networks through a central hub','An internet gateway for large enterprises','A payment gateway for AWS Marketplace'],correct:1,explanation:'AWS Transit Gateway acts as a cloud router, connecting VPCs and on-premises networks through a central hub, simplifying network topology.'},
{id:'ccp124',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Quantum Ledger Database (QLDB)?',options:['A quantum computing database','A fully managed ledger database providing a cryptographically verifiable transaction log','A database for financial quantum models','A ledger for tracking AWS service usage'],correct:1,explanation:'Amazon QLDB is a fully managed ledger database with a transparent, immutable, and cryptographically verifiable transaction log.'},
{id:'ccp125',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the purpose of AWS service quotas (formerly limits)?',options:['To prevent customers from using too many services','Maximum values for resources and API requests to protect the AWS infrastructure and the customer account','Price limits on AWS services','The number of support cases you can open'],correct:1,explanation:'Service quotas are limits on the maximum number of resources you can create and the rate of API calls, protecting both AWS infrastructure and your account.'},
{id:'ccp126',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon EventBridge?',options:['An event venue booking service','A serverless event bus that connects applications using real-time data from your own apps, SaaS, and AWS services','A physical event monitoring dashboard','A bridge between two VPCs'],correct:1,explanation:'Amazon EventBridge is a serverless event bus that makes it easier to build event-driven applications using events from AWS services, your apps, and SaaS.'},
{id:'ccp127',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is IAM Identity Center (formerly SSO)?',options:['A single sign-on service for websites','A service for centrally managing SSO access to multiple AWS accounts and business applications','A two-factor authentication service','An identity theft protection service'],correct:1,explanation:'AWS IAM Identity Center provides centralized SSO access to all your AWS accounts and business applications from one place.'},
{id:'ccp128',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon MemoryDB for Redis?',options:['A physical memory management tool','A Redis-compatible, durable, in-memory database service for ultra-fast performance','A memory profiling service','A Redis documentation service'],correct:1,explanation:'Amazon MemoryDB for Redis is a Redis-compatible, fully managed in-memory database that provides fast performance with Multi-AZ durability.'},
{id:'ccp129',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is "infrastructure as code" (IaC)?',options:['Writing code that runs on physical infrastructure only','Managing and provisioning infrastructure through machine-readable configuration files rather than manual processes','A programming language for hardware','Infrastructure monitoring using code metrics'],correct:1,explanation:'IaC manages infrastructure through code (like CloudFormation or Terraform), enabling version control, automation, and repeatable deployments.'},
{id:'ccp130',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS CodeBuild?',options:['A visual website builder','A fully managed build service that compiles source code, runs tests, and produces deployment artifacts','A CI/CD pipeline service','A code review tool'],correct:1,explanation:'AWS CodeBuild is a fully managed continuous integration service that compiles source code, runs unit tests, and produces ready-to-deploy software packages.'},
{id:'ccp131',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is VPC Flow Logs?',options:['A log of all network requests to websites','Captures information about IP traffic going to and from network interfaces in your VPC','A log of all API calls','A physical network cable log'],correct:1,explanation:'VPC Flow Logs capture information about the IP traffic going to and from network interfaces in your VPC for security and troubleshooting.'},
{id:'ccp132',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Outposts?',options:['Remote AWS offices','Fully managed infrastructure that extends AWS services and APIs to virtually any on-premises or edge location','Outdoor surveillance services','External partner network nodes'],correct:1,explanation:'AWS Outposts brings native AWS services, infrastructure, and operating models to on-premises and edge locations for hybrid cloud deployments.'},
{id:'ccp133',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is AWS Compute Optimizer?',options:['A tool to physically optimize server hardware','Recommends optimal AWS compute resources (EC2, Lambda, EBS) based on actual usage data to reduce costs','A cost comparison service for different cloud providers','A calculator for compute pricing'],correct:1,explanation:'AWS Compute Optimizer uses ML to analyze usage metrics and recommend optimal compute resources to reduce costs and improve performance.'},
{id:'ccp134',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Wavelength?',options:['A radio frequency management service','Infrastructure deployments within telecom providers to deliver ultra-low latency apps for 5G mobile devices','A light-based networking standard','A low-power IoT wireless protocol'],correct:1,explanation:'AWS Wavelength embeds compute and storage within 5G networks, enabling developers to build ultra-low-latency applications for mobile edge computing.'},
{id:'ccp135',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What does TCO (Total Cost of Ownership) mean in cloud context?',options:['The total cost of your monthly AWS bill only','The full cost comparison including hardware, software, staff, facilities, and operational costs of on-premises vs cloud','The cost of transferring data out of AWS','The total number of services you use'],correct:1,explanation:'TCO analysis compares the total costs of running on-premises (hardware, facilities, staff, software) vs cloud, often showing cloud has lower TCO.'},
{id:'ccp136',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Keyspaces?',options:['A key management service','A scalable, serverless, and highly available Apache Cassandra-compatible database service','A keyboard shortcut service','A key-value store optimized for gaming'],correct:1,explanation:'Amazon Keyspaces is a serverless, Apache Cassandra-compatible database service that is scalable, available, and fully managed.'},
{id:'ccp137',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Lake Formation?',options:['A water management service','A service that makes it easy to set up a secure data lake in days','A cloud storage tier for archives','A formation training service'],correct:1,explanation:'AWS Lake Formation simplifies the creation of secure data lakes, handling the complex tasks of data ingestion, cataloging, security, and governance.'},
{id:'ccp138',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is an IAM Role?',options:['A job title for AWS employees','An IAM identity that can be assumed by services, applications, or users that need temporary access to AWS resources','A permanent set of permissions for a user','An EC2 instance type designation'],correct:1,explanation:'IAM Roles provide temporary credentials and are assumed by EC2 instances, Lambda functions, or users to access AWS resources without embedding credentials.'},
{id:'ccp139',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Lookout for Metrics?',options:['A telescope rental service','A service that uses ML to automatically detect anomalies in business metrics and identify their root causes','A performance monitoring dashboard','A KPI tracking spreadsheet'],correct:1,explanation:'Amazon Lookout for Metrics automatically detects and diagnoses anomalies in business and operational metrics using ML, without requiring ML expertise.'},
{id:'ccp140',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is an S3 bucket policy?',options:['A lifecycle policy for objects','A resource-based policy attached to an S3 bucket that grants access permissions to the bucket and the objects in it','A CORS policy for S3','A replication policy'],correct:1,explanation:'An S3 bucket policy is a JSON-based resource policy that controls access to an S3 bucket and its objects, allowing or denying specific actions.'},
{id:'ccp141',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon CloudSearch?',options:['A legal discovery tool','A fully managed search service that makes it easy to set up, manage, and scale a search solution for your website or application','A cloud provider comparison site','A DNS search service'],correct:1,explanation:'Amazon CloudSearch is a fully managed service that makes it easy to set up, manage, and scale a custom search solution.'},
{id:'ccp142',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Pinpoint?',options:['A GPS location service','A flexible marketing communications service for sending targeted messages via email, SMS, push, and voice','A map annotation tool','A precision time synchronization service'],correct:1,explanation:'Amazon Pinpoint is a flexible communications service for marketing, transactional, and bulk messaging campaigns via email, SMS, push, and voice channels.'},
{id:'ccp143',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS Certificate Manager (ACM)?',options:['A diploma verification service','Provisions, manages, and deploys SSL/TLS certificates for use with AWS services','A compliance certification tracker','A management certification training service'],correct:1,explanation:'AWS ACM handles the complexity of creating, storing, and renewing SSL/TLS certificates for use with AWS services at no cost.'},
{id:'ccp144',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS CodeDeploy?',options:['A cloud storage deployment','A fully managed deployment service that automates software deployments to EC2, Lambda, and on-premises servers','A code distribution CDN','A developer marketplace'],correct:1,explanation:'AWS CodeDeploy automates code deployments to any instance—including EC2, Lambda, and on-premises—minimizing downtime during application updates.'},
{id:'ccp145',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the difference between public and private subnets in a VPC?',options:['Public subnets cost more','Public subnets have a route to an internet gateway; private subnets do not, making resources inaccessible from the internet','Public subnets are for databases; private subnets are for web servers','There is no difference'],correct:1,explanation:'Public subnets route traffic to an internet gateway, enabling direct internet access. Private subnets have no internet gateway route, keeping resources isolated.'},
{id:'ccp146',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Fraud Detector?',options:['A physical fraud investigation service','A fully managed service using ML to identify potentially fraudulent online activities','A financial audit tool','A customer identity verification service'],correct:1,explanation:'Amazon Fraud Detector uses ML to detect potentially fraudulent activities online, such as fake accounts and payment fraud, in real time.'},
{id:'ccp147',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Ground Station?',options:['A weather station monitoring service','A fully managed service to control satellite communications, process data, and scale operations','A ground transportation logistics tool','An underground data center tier'],correct:1,explanation:'AWS Ground Station is a fully managed service for controlling satellite communications and processing satellite data using AWS global infrastructure.'},
{id:'ccp148',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is the purpose of Resource Tags in AWS billing?',options:['To label physical servers','To categorize AWS resources for cost allocation, allowing you to track spending by project, team, or environment','To tag security vulnerabilities','To label public IP addresses'],correct:1,explanation:'Resource tags are key-value pairs applied to AWS resources. Cost allocation tags help you track and allocate costs to specific projects or teams.'},
{id:'ccp149',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon AppStream 2.0?',options:['A music streaming service','A fully managed application streaming service that delivers desktop applications to any device through a browser','A video live-streaming platform','An app update distribution service'],correct:1,explanation:'Amazon AppStream 2.0 streams desktop applications from AWS to any device with a web browser, without needing to install applications locally.'},
{id:'ccp150',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the AWS Command Line Interface (CLI)?',options:['A physical hardware control panel','A unified tool to manage AWS services from the command line, enabling scripting and automation','A web-based management console','A chat-based support tool'],correct:1,explanation:'The AWS CLI allows you to interact with AWS services using commands in your terminal, enabling automation and scripting of AWS operations.'},
{id:'ccp151',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company stores customer PII in S3 and must detect if any sensitive data is accidentally made public. Which service combination should they use?',options:['Amazon GuardDuty + AWS Shield','Amazon Macie + S3 Block Public Access','AWS Config + Amazon Inspector','AWS Trusted Advisor + AWS WAF'],correct:1,explanation:'Amazon Macie uses ML to discover and protect sensitive data (PII) in S3. Combined with S3 Block Public Access, it provides detection and prevention of accidental data exposure.'},
{id:'ccp152',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A startup wants to reduce their infrastructure costs. They have a predictable baseline load running 24/7 and occasional spikes. What is the MOST cost-effective EC2 purchasing strategy?',options:['100% On-Demand instances','Reserved Instances for baseline + Spot Instances for spikes','Spot Instances for everything','Dedicated Hosts for all workloads'],correct:1,explanation:'Reserved Instances provide up to 72% savings for the steady, predictable baseline. Spot Instances (up to 90% off) handle spikes where interruption is tolerable—the combination maximizes savings.'},
{id:'ccp153',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A security audit finds that multiple IAM users share the same set of permissions needed for their job function. What is the BEST practice to manage this efficiently while maintaining least privilege?',options:['Give each user AdministratorAccess to avoid permission gaps','Create an IAM Group with the required policy and add users to the group','Attach the same policy directly to each individual user','Create a single shared IAM user for the team'],correct:1,explanation:'IAM Groups let you assign permissions once at the group level. All members inherit those permissions, ensuring consistency and making changes easy—one edit affects all members.'},
{id:'ccp154',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A web application needs a database that automatically scales to handle millions of requests per second with single-digit millisecond latency and no schema management. Which service is the BEST fit?',options:['Amazon RDS for MySQL','Amazon Redshift','Amazon DynamoDB','Amazon Aurora PostgreSQL'],correct:2,explanation:'DynamoDB is a serverless NoSQL database with automatic scaling to any throughput, single-digit millisecond performance, and no schema to manage—ideal for high-scale, low-latency use cases.'},
{id:'ccp155',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company runs several departments using AWS and wants each department to see only their own costs while a central team manages consolidated billing. Which AWS feature enables this?',options:['AWS Cost Explorer filters','IAM permission boundaries','AWS Organizations with Cost Allocation Tags','Separate AWS accounts with no organization'],correct:2,explanation:'AWS Organizations enables consolidated billing. Cost Allocation Tags let you label resources by department so each team can filter Cost Explorer to view only their own spending.'},
{id:'ccp156',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company is migrating from on-premises to AWS. They want to use the cloud\'s ability to automatically adjust resources during peak shopping seasons and scale down afterward. Which cloud characteristic does this describe?',options:['Fault tolerance','Elasticity','Durability','Portability'],correct:1,explanation:'Elasticity is the ability to automatically acquire resources when demand rises and release them when demand falls—exactly what seasonal workload patterns require.'},
{id:'ccp157',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A developer accidentally committed AWS access keys to a public GitHub repository. What should be the IMMEDIATE first action?',options:['Change the GitHub repository to private','Deactivate or delete the exposed access keys in IAM immediately','Enable MFA on the IAM user','Rotate the root user password'],correct:1,explanation:'Exposed access keys must be deactivated or deleted immediately as the first priority. Once keys are in public repos they should be considered compromised—assume they have already been used maliciously.'},
{id:'ccp158',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'An application currently uses a self-managed MySQL database on EC2. The team wants to reduce operational overhead for backups, patching, and replication. Which migration path requires the LEAST operational overhead?',options:['Move MySQL to a larger EC2 instance','Migrate to Amazon RDS for MySQL','Migrate to Amazon Redshift','Migrate to DynamoDB'],correct:1,explanation:'Amazon RDS is a managed relational database service that handles backups, patching, Multi-AZ replication, and failover automatically—dramatically reducing operational overhead vs self-managed EC2.'},
{id:'ccp159',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A financial services company must demonstrate that their AWS environment meets PCI DSS compliance requirements to auditors. Which AWS service provides the compliance reports they need?',options:['AWS Trusted Advisor','AWS Artifact','Amazon Inspector','AWS Security Hub'],correct:1,explanation:'AWS Artifact is the self-service portal for AWS compliance documentation including SOC reports, PCI DSS Attestation of Compliance, ISO certifications, and other audit reports.'},
{id:'ccp160',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company wants to decouple a monolithic application into microservices. Producer services generate messages at peak times faster than consumers can process them. Which service should they use to absorb this burst?',options:['Amazon CloudFront','AWS Lambda','Amazon SQS','Amazon CloudWatch'],correct:2,explanation:'Amazon SQS is a managed message queue that decouples producers and consumers. Messages are stored in the queue until consumers are ready, absorbing bursts without dropping messages.'},
{id:'ccp161',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'Under the AWS Shared Responsibility Model, who is responsible for patching the operating system on an Amazon EC2 instance?',options:['AWS, as they manage all servers','The customer, as the OS is their responsibility inside the cloud','AWS patches the OS but the customer configures it','Neither party; EC2 patches automatically'],correct:1,explanation:'EC2 gives customers full control of the OS. The customer is responsible for patching and maintaining the guest OS. AWS handles the underlying hypervisor and physical hardware.'},
{id:'ccp162',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company wants to receive an alert when their monthly AWS bill is projected to exceed $10,000. Which service should they configure?',options:['AWS Cost Explorer with a saved report','AWS Budgets with a cost budget alert','Amazon CloudWatch billing alarm only','AWS Trusted Advisor cost check'],correct:1,explanation:'AWS Budgets lets you set a monthly cost budget of $10,000 and sends an alert via email or SNS when actual or forecasted costs exceed that threshold.'},
{id:'ccp163',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company wants to host a static website (HTML, CSS, JavaScript) at the lowest possible cost with high availability globally. What is the MOST cost-effective solution?',options:['EC2 instances in multiple regions','Amazon S3 static website hosting + Amazon CloudFront','Amazon Lightsail multi-region setup','AWS Elastic Beanstalk with auto scaling'],correct:1,explanation:'S3 static website hosting is extremely cheap (pay per GB stored and requests). Adding CloudFront distributes content via edge locations worldwide for low latency—the most cost-effective global static site approach.'},
{id:'ccp164',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company needs to ensure that no resources in any of their AWS accounts can be deployed outside of the us-east-1 and eu-west-1 regions. What is the MOST effective way to enforce this at scale?',options:['Train developers to only use approved regions','Set IAM user policies restricting regions for each user','Apply a Service Control Policy (SCP) via AWS Organizations','Use AWS Config rules in each account'],correct:2,explanation:'SCPs in AWS Organizations apply to all accounts and OUs, enforcing guardrails that cannot be overridden by any account administrator—the most scalable way to restrict regions organization-wide.'},
{id:'ccp165',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company is evaluating moving to AWS. They currently spend $2M/year on data center hardware, $500K on facilities/power, and $300K on IT staff for infrastructure. Their estimated AWS bill would be $1.4M/year. What concept does this comparison represent?',options:['ROI calculation','TCO (Total Cost of Ownership) analysis','Break-even analysis','Opportunity cost analysis'],correct:1,explanation:'TCO analysis compares the full on-premises costs (hardware, facilities, power, staff) against cloud costs. In this case, $2.8M on-premises vs $1.4M in the cloud—TCO shows cloud is significantly cheaper.'},
{id:'ccp166',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'An application needs to process images uploaded to S3 and store metadata in a database within seconds of upload. What is the MOST serverless and cost-effective architecture?',options:['EC2 worker polling S3 every minute','S3 Event Notification → Lambda → DynamoDB','EC2 Auto Scaling Group + RDS','Kinesis Data Streams + EC2'],correct:1,explanation:'S3 event notifications trigger Lambda automatically on upload—no polling needed. Lambda processes the image and writes to DynamoDB. This is fully serverless, event-driven, and you pay only for actual executions.'},
{id:'ccp167',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company uses AWS and their on-premises Active Directory for identity management. They want employees to use their existing corporate credentials to access AWS without creating separate IAM users. Which solution achieves this?',options:['Create IAM users that mirror all AD accounts','Use AWS IAM Identity Center with AD as the identity source','Share the root user credentials with employees','Use Amazon Cognito for corporate SSO'],correct:1,explanation:'IAM Identity Center (formerly SSO) integrates with existing identity providers including Active Directory, allowing employees to use corporate credentials for SSO access to AWS accounts and applications.'},
{id:'ccp168',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company has 3 AWS accounts using different amounts of data transfer, S3 storage, and EC2 hours. They consolidate under AWS Organizations. How might their overall bill change?',options:['It will always increase because of management overhead','It may decrease because combined usage can qualify for volume pricing tiers','It will stay exactly the same','It will increase because Organizations adds a premium'],correct:1,explanation:'Consolidated billing combines usage across all member accounts. Higher aggregate usage may qualify for volume pricing tiers (e.g., S3 pricing decreases per-GB as total usage increases), potentially lowering the total bill.'},
{id:'ccp169',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company wants to run a batch machine learning training job that takes 6 hours, can tolerate interruption, and needs to minimize cost. Which EC2 purchasing option is BEST?',options:['On-Demand with checkpointing','Reserved Instance 1-year term','Spot Instance with checkpointing','Dedicated Host'],correct:2,explanation:'Spot Instances offer up to 90% savings over On-Demand. For a 6-hour batch ML job that can checkpoint and resume if interrupted, Spot is the most cost-effective choice.'},
{id:'ccp170',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company\'s application in us-east-1 must continue serving traffic even if an entire AWS Region becomes unavailable. Which architectural approach achieves this?',options:['Deploy across multiple Availability Zones in us-east-1','Use a second Region (e.g., eu-west-1) with Route 53 failover routing','Enable Multi-AZ on their RDS database','Use CloudFront to cache responses'],correct:1,explanation:'Multi-AZ protects against AZ failure but not full Region failure. To survive a Region outage, you must deploy to a second Region and use Route 53 failover routing to redirect traffic automatically.'},
{id:'ccp171',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'Which statement BEST describes what AWS CloudTrail provides that Amazon CloudWatch does NOT?',options:['CloudTrail monitors application performance metrics; CloudWatch does not','CloudTrail records who made AWS API calls and when; CloudWatch monitors performance and operational metrics','CloudTrail monitors network traffic; CloudWatch monitors API calls','They are identical services with different names'],correct:1,explanation:'CloudTrail is the audit/compliance tool—it logs every API call (who, what, when, from where) for governance and forensics. CloudWatch is the operational monitoring tool—it collects metrics, logs, and triggers alarms on performance data.'},
{id:'ccp172',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company needs to migrate 80TB of on-premises data to S3. Their internet connection is 100 Mbps shared with production traffic. Uploading over the internet would take months and impact operations. What is the BEST solution?',options:['Compress the data and upload during off-hours','Use AWS Direct Connect','Order an AWS Snowball Edge device','Use AWS DataSync over the existing connection'],correct:2,explanation:'80TB over a 100Mbps connection (even unshared) would take weeks and degrade production. AWS Snowball Edge ships a physical device you load data onto locally and ship to AWS—much faster for large offline transfers.'},
{id:'ccp173',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company wants to use AWS services but must keep certain sensitive workloads on-premises due to data sovereignty regulations, while integrating them with cloud workloads. Which deployment model does this describe?',options:['Public cloud only','Private cloud only','Hybrid cloud','Multi-cloud'],correct:2,explanation:'A hybrid cloud connects on-premises infrastructure with cloud services, allowing regulated/sensitive workloads to stay on-premises while other workloads use cloud services—all integrated together.'},
{id:'ccp174',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company wants to automatically remediate non-compliant S3 buckets that have public access enabled. Which AWS services should they combine?',options:['Amazon Macie + Amazon Inspector','AWS Config rules + AWS Systems Manager Automation','AWS Trusted Advisor + AWS Lambda','Amazon GuardDuty + AWS WAF'],correct:1,explanation:'AWS Config rules continuously evaluate S3 bucket configurations. When a rule detects a non-compliant resource, it can trigger Systems Manager Automation runbooks to automatically remediate the issue (e.g., block public access).'},
{id:'ccp175',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company pays for EC2 instances in several sizes (t3.medium, m5.large, c5.xlarge) across multiple services. They want maximum pricing flexibility without being locked to specific instance types or sizes. Which commitment option provides this?',options:['Standard Reserved Instances','Convertible Reserved Instances','Compute Savings Plans','EC2 Instance Savings Plans'],correct:2,explanation:'Compute Savings Plans apply automatically to any EC2 instance family, size, region, OS, and tenancy—plus Lambda and Fargate. They offer up to 66% savings with maximum flexibility, unlike Reserved Instances which lock you to specific configurations.'},
{id:'ccp176',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company\'s application must store session state and share it across multiple EC2 instances behind a load balancer, so any instance can serve any user request. Which approach is BEST?',options:['Store session state on each EC2 instance\'s local disk','Use EC2 instance store for session data','Store session state in Amazon ElastiCache (Redis)','Use EBS volumes shared across instances'],correct:2,explanation:'Storing sessions in ElastiCache Redis makes session data available to all EC2 instances equally. Local disk or instance store is lost when an instance is replaced. EBS cannot be shared across multiple running instances.'},
{id:'ccp177',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'Which of the following is SOLELY the responsibility of AWS under the Shared Responsibility Model?',options:['Configuring IAM user passwords','Patching customer EC2 operating systems','Physical security of data center facilities','Encrypting customer data in S3'],correct:2,explanation:'Physical security of data centers (locks, guards, cameras, environmental controls) is entirely AWS\'s responsibility—customers have no access or control over physical infrastructure. All other options are customer responsibilities.'},
{id:'ccp178',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company wants to send automated email and SMS notifications when an Auto Scaling event occurs. Which AWS service should receive the Auto Scaling notification and fan it out to multiple subscribers?',options:['Amazon SQS','Amazon SNS','AWS Lambda','Amazon EventBridge'],correct:1,explanation:'Amazon SNS is a pub/sub messaging service. Auto Scaling can publish events to an SNS topic, which then fans out to multiple subscriptions—email endpoints, SMS, Lambda functions, SQS queues—simultaneously.'},
{id:'ccp179',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company needs to store database passwords and API keys used by their applications, with automatic rotation every 30 days and audit logs of every access. Which service is purpose-built for this?',options:['AWS KMS','AWS Systems Manager Parameter Store (Standard)','AWS Secrets Manager','Amazon S3 with encryption'],correct:2,explanation:'AWS Secrets Manager is purpose-built for secrets management with built-in automatic rotation for supported services, fine-grained access control, and integration with CloudTrail for access auditing.'},
{id:'ccp180',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company is choosing between AWS Support plans. They need access to AWS Support API, a full set of Trusted Advisor checks, and a response time under 1 hour for production system failures. Which is the MINIMUM plan that meets all these requirements?',options:['Basic','Developer','Business','Enterprise'],correct:2,explanation:'Business Support provides: access to all Trusted Advisor checks, AWS Support API access, and 1-hour response SLA for production system impairments. Developer only provides 12-hour business hours response; Basic has no technical support.'},
{id:'ccp181',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company runs hundreds of AWS accounts across multiple business units. The security team needs to enforce a rule that prevents ANY account from disabling AWS CloudTrail, even account administrators. Which service and feature achieves this?',options:['AWS Config rule deployed to every account','IAM permission boundary on all admin roles','Service Control Policy (SCP) in AWS Organizations denying cloudtrail:StopLogging','AWS CloudTrail log file validation in each account'],correct:2,explanation:'SCPs in AWS Organizations are the only mechanism that can restrict even account root users and administrators. An SCP denying cloudtrail:StopLogging applies to all principals in all member accounts and cannot be overridden at the account level.'},
{id:'ccp182',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'An e-commerce company experiences traffic spikes every Friday at 8 PM that are 10x normal load, lasting about 2 hours. The rest of the week is steady and predictable. Which purchasing strategy minimizes cost while ensuring capacity?',options:['All Spot Instances — cheapest option','Reserved Instances for 100% of peak capacity','Reserved Instances for baseline load + Scheduled Reserved Instances or On-Demand for the Friday spikes','On-Demand for everything to stay flexible'],correct:2,explanation:'Reserved Instances cover the steady baseline at up to 72% savings. The predictable Friday spike is best handled with Scheduled Reserved Instances (or On-Demand if scheduled RIs are unavailable) — Spot is too risky for customer-facing spikes since AWS can reclaim them.'},
{id:'ccp183',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A solutions architect reviews a workload where a single EC2 instance runs both the web server and database. A hardware failure would cause complete downtime. Which Well-Architected pillar is MOST violated, and what is the PRIMARY fix?',options:['Cost Optimization — move to serverless','Performance Efficiency — use a larger instance','Reliability — separate tiers and deploy across multiple AZs','Operational Excellence — add CloudWatch monitoring'],correct:2,explanation:'Reliability requires eliminating single points of failure. Separating the web tier from the database tier and deploying each across multiple AZs (Auto Scaling Group + RDS Multi-AZ) directly addresses the SPOF risk described.'},
{id:'ccp184',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company wants to reduce their AWS bill. AWS Compute Optimizer recommends downsizing several EC2 instances, and Cost Explorer shows $3,000/month on NAT Gateway data processing charges. Which TWO actions would reduce costs? (Choose the best single answer that captures both.)',options:['Purchase Reserved Instances and enable S3 Transfer Acceleration','Downsize over-provisioned EC2 instances and move S3-to-S3 traffic through VPC Gateway Endpoints instead of NAT Gateway','Enable detailed billing and set up AWS Budgets alerts','Switch all instances to Spot and use Savings Plans'],correct:1,explanation:'Right-sizing EC2 per Compute Optimizer reduces compute spend. S3 traffic routed through a free VPC Gateway Endpoint bypasses the NAT Gateway entirely, eliminating those data processing charges. These are two of the most common quick wins Cost Explorer surfaces.'},
{id:'ccp185',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company\'s compliance framework requires that all data stored in S3 must be encrypted, and encryption must be enforced regardless of how objects are uploaded. Which S3 feature enforces this server-side?',options:['S3 Versioning','S3 Default Encryption (SSE-S3 or SSE-KMS) with a bucket policy denying unencrypted uploads','S3 Object Lock','S3 Transfer Acceleration'],correct:1,explanation:'S3 Default Encryption ensures all new objects are encrypted at rest. Adding a bucket policy with a condition denying s3:PutObject when x-amz-server-side-encryption is absent ensures no unencrypted object can be uploaded, enforcing compliance programmatically.'},
{id:'ccp186',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A startup is building a multi-tenant SaaS app on AWS. Each tenant\'s data must be completely isolated. The team wants to use a single AWS account for cost simplicity. Which approach provides the STRONGEST data isolation without separate accounts?',options:['Store all tenants in one DynamoDB table with a partition key per tenant','Use separate S3 buckets per tenant with bucket policies and separate RDS schemas per tenant','Use a single RDS database with row-level tenant IDs','Deploy one Lambda function per tenant'],correct:1,explanation:'Separate S3 buckets with bucket policies enforcing tenant-specific access, combined with separate RDS schemas (or databases), provides strong logical isolation within a single account. Row-level isolation in a shared table is weaker — a misconfigured query could expose cross-tenant data.'},
{id:'ccp187',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company is planning to migrate from on-premises to AWS using a "lift and shift" approach. Which migration strategy does this describe, and what is its PRIMARY characteristic?',options:['Re-architect — redesign the application natively for cloud','Re-platform — make targeted optimizations without changing core architecture','Rehost — move applications to the cloud with no changes (same architecture)','Retire — decommission the application entirely'],correct:2,explanation:'"Lift and shift" is Rehost: move VMs and databases to EC2 and RDS with minimal changes. It is the fastest migration path with least risk, but doesn\'t take full advantage of cloud-native features. The 6 Rs of migration are Rehost, Replatform, Repurchase, Re-architect, Retire, and Retain.'},
{id:'ccp188',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company recently suffered a security incident where an EC2 instance was compromised and used to make unauthorized API calls. Which TWO services would have provided the EARLIEST detection? (Select the best combined answer.)',options:['AWS WAF and Amazon Inspector','Amazon GuardDuty (unusual API activity) and AWS CloudTrail (API audit log)','AWS Config and Amazon Macie','AWS Shield and AWS Trusted Advisor'],correct:1,explanation:'GuardDuty continuously analyzes CloudTrail, VPC Flow Logs, and DNS logs using ML to detect unusual API calls and credential abuse — it would alert on the anomalous behavior. CloudTrail provides the forensic record of exactly which API calls were made, by whom, from where, enabling post-incident investigation.'},
{id:'ccp189',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company runs a stateful application where users must always reach the same EC2 instance during their session. They are deploying an Elastic Load Balancer. Which ELB feature and type should they use?',options:['Network Load Balancer with cross-zone load balancing','Application Load Balancer with sticky sessions (session affinity)','Classic Load Balancer with health checks only','Gateway Load Balancer with target groups'],correct:1,explanation:'Sticky sessions (session affinity) on an Application Load Balancer use a cookie to route a client\'s requests to the same target for the duration of the session. ALB operates at Layer 7 and supports sticky sessions natively — the right tool for HTTP/HTTPS stateful applications.'},
{id:'ccp190',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company has a 3-year commitment and wants maximum EC2 savings. They run a mix of instance families and sizes across multiple regions and also use Lambda. Which savings option provides the MOST flexibility across all these services?',options:['Standard Reserved Instances in each region','Convertible Reserved Instances','Compute Savings Plans','EC2 Instance Savings Plans'],correct:2,explanation:'Compute Savings Plans apply automatically across EC2 (any family, size, region, OS, tenancy), AWS Lambda, and AWS Fargate — the broadest coverage. EC2 Instance Savings Plans are limited to one instance family per region. Convertible RIs are flexible but don\'t cover Lambda or Fargate.'},
{id:'ccp191',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company needs to run a high-performance computing (HPC) simulation that requires extremely low latency between nodes and high bandwidth networking. Which EC2 feature should they enable?',options:['Multi-AZ deployment','Enhanced Networking with Elastic Fabric Adapter (EFA)','EC2 Placement Groups (Spread strategy)','Auto Scaling with predictive scaling'],correct:1,explanation:'Elastic Fabric Adapter (EFA) enables ultra-low latency OS-bypass networking between EC2 instances, purpose-built for HPC tightly-coupled workloads. Cluster Placement Groups co-locate instances physically for low latency. Spread placement is for fault tolerance, not performance.'},
{id:'ccp192',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company has an on-premises application that calls an AWS API millions of times per day. Network latency to the public AWS endpoint is causing performance issues. What are the TWO best options to reduce latency? (Select the best combined answer.)',options:['Purchase more bandwidth from the ISP and compress API payloads','Use AWS Direct Connect for a dedicated private connection and/or move the application to EC2 within the same AWS Region','Enable AWS Shield Advanced for faster routing','Use Amazon CloudFront to cache API responses'],correct:1,explanation:'Direct Connect provides a dedicated private circuit to AWS bypassing the public internet, drastically reducing latency and increasing throughput. Moving the application to EC2 in the same region as the API eliminates the on-premises round-trip entirely. CloudFront can cache idempotent GET responses but doesn\'t help with dynamic write-heavy API calls.'},
{id:'ccp193',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A developer is building a mobile app that needs to access a user\'s photos stored in S3. The app authenticates users with Google Sign-In. Which AWS service allows the app to exchange the Google token for temporary AWS credentials to access S3?',options:['AWS IAM users with long-term access keys','Amazon Cognito Identity Pools (Federated Identities)','AWS SSO / IAM Identity Center','AWS Directory Service'],correct:1,explanation:'Amazon Cognito Identity Pools allow users to authenticate with external identity providers (Google, Facebook, Apple, SAML) and receive temporary, scoped AWS credentials via STS. This is the standard pattern for granting mobile/web app users direct access to AWS resources without managing IAM users.'},
{id:'ccp194',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'An application writes 1,000 records per second to a DynamoDB table. After several months, read performance on older records degrades and costs increase. The team realizes they only need fast access to the last 90 days of data, and older records can be archived cheaply. Which DynamoDB feature automates this lifecycle?',options:['DynamoDB Streams','DynamoDB Global Tables','DynamoDB Time to Live (TTL) with export to S3','DynamoDB DAX'],correct:2,explanation:'DynamoDB TTL lets you set an expiration timestamp per item. When items expire, DynamoDB deletes them automatically at no extra cost. Combining TTL with DynamoDB Streams → Lambda → S3 (or DynamoDB export to S3) archives data before deletion, keeping the table lean and costs low.'},
{id:'ccp195',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company notices that data transfer costs are a significant portion of their AWS bill. They serve users globally from an S3 bucket in us-east-1. What is the MOST cost-effective architectural change to reduce data transfer costs?',options:['Move all data to S3 Glacier to reduce storage costs','Enable S3 Transfer Acceleration','Add CloudFront in front of S3 to cache content at edge locations near users','Move to a larger EC2 instance with more network bandwidth'],correct:2,explanation:'CloudFront caches S3 content at edge locations. Subsequent requests are served from the edge without fetching from the origin, dramatically reducing S3 outbound data transfer charges (CloudFront\'s per-GB rate to end users is lower than S3\'s, and cache hits eliminate origin transfer altogether).'},
{id:'ccp196',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company is migrating their Oracle data warehouse to AWS. They want a cloud-native managed solution optimized for analytical queries (OLAP) across petabytes of data. Which service is the BEST fit?',options:['Amazon RDS for Oracle','Amazon DynamoDB','Amazon Redshift','Amazon Aurora PostgreSQL'],correct:2,explanation:'Amazon Redshift is a fully managed, petabyte-scale cloud data warehouse optimized for OLAP analytical workloads with columnar storage and massively parallel processing. RDS and Aurora are OLTP databases. DynamoDB is a NoSQL key-value store — none are designed for petabyte-scale analytics.'},
{id:'ccp197',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company must ensure that EC2 instances in a private subnet can download software updates from the internet but cannot accept any inbound connections from the internet. Which component achieves this?',options:['Internet Gateway attached to the private subnet','VPC Peering connection','NAT Gateway in a public subnet with a route from the private subnet','Elastic IP address on each private instance'],correct:2,explanation:'A NAT Gateway allows instances in private subnets to initiate outbound internet connections (for updates, patches) while blocking all unsolicited inbound traffic. It sits in a public subnet; private subnet route tables point 0.0.0.0/0 to the NAT Gateway, not an Internet Gateway.'},
{id:'ccp198',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company wants to test a new version of their application alongside the current version, gradually shifting traffic from v1 to v2 while monitoring error rates. Which deployment strategy does this describe?',options:['Blue/green deployment — switch 100% at cutover','Canary deployment — route a small percentage of traffic to v2, increase gradually','In-place deployment — update all instances simultaneously','Disaster recovery — run v2 only in a secondary region'],correct:1,explanation:'A canary deployment routes a small initial percentage of traffic (e.g., 5%) to the new version, monitors metrics, and progressively increases traffic if healthy. Blue/green cuts over 100% at once (with fast rollback). In-place updates all instances together — high risk. AWS CodeDeploy, ALB weighted target groups, and Route 53 weighted routing all support canary patterns.'},
{id:'ccp199',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A healthcare company needs to store medical imaging files (very large objects, up to 5 GB each). They need low-latency access and the objects are accessed frequently in the first 30 days, rarely after 6 months, and almost never after 2 years. Which S3 feature automatically optimizes storage costs for this pattern?',options:['S3 Lifecycle policy moving objects: Standard → Standard-IA after 30 days → Glacier after 180 days','S3 Versioning with MFA delete','S3 Block Public Access','S3 Requester Pays'],correct:0,explanation:'S3 Lifecycle rules automate tiering based on object age. Standard (frequent access) → Standard-IA after 30 days (lower storage cost, retrieval fee) → S3 Glacier after 180 days (archive, very low cost) perfectly matches the described access pattern and requires no application changes.'},
{id:'ccp200',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'After enabling Cost Allocation Tags and reviewing Cost Explorer, a company discovers that 40% of their monthly spend comes from EC2 instances tagged "environment: dev" that run 24/7. These dev instances are only used 8 hours a day, 5 days a week. What is the MOST cost-effective solution?',options:['Migrate all dev instances to Spot','Purchase Reserved Instances for dev workloads','Use AWS Instance Scheduler or Lambda to stop dev instances outside working hours','Move dev workloads to AWS Fargate'],correct:2,explanation:'Dev instances used only 40 hours/week (24%) don\'t justify Reserved Instances or Spot complexity. Automatically stopping them outside working hours (using AWS Instance Scheduler, a Lambda cron, or EC2 instance start/stop automation) eliminates ~76% of their runtime costs immediately.'},
{id:'ccp201',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company stores credit card data and must comply with PCI DSS. They want to avoid storing raw card numbers at all. Which AWS service allows applications to process payments while replacing sensitive card data with a non-sensitive token?',options:['AWS KMS encryption','Amazon Macie data classification','AWS Payment Cryptography tokenization','AWS Secrets Manager'],correct:2,explanation:'AWS Payment Cryptography provides payment-grade tokenization and cryptography that replaces sensitive card data (PAN) with a non-sensitive token, reducing PCI DSS scope. KMS encrypts data but the application still handles the raw number. Macie discovers sensitive data but doesn\'t tokenize it.'},
{id:'ccp202',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company needs a database for a social network application that stores user relationships as a highly connected graph (friends, followers, mutual connections). Queries must traverse many relationship hops efficiently. Which database type and AWS service is BEST suited?',options:['Amazon RDS (relational) — use complex JOINs','Amazon DynamoDB (NoSQL) — use adjacency list pattern','Amazon Neptune (graph database)','Amazon Redshift (data warehouse)'],correct:2,explanation:'Amazon Neptune is a purpose-built graph database supporting Property Graph (Gremlin) and RDF (SPARQL) models. Graph databases traverse relationships natively without expensive JOINs. Social networks, knowledge graphs, fraud detection, and recommendation engines are Neptune\'s primary use cases.'},
{id:'ccp203',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company is designing their AWS network architecture. They want to minimize the blast radius if one part of the system is compromised, applying network-level isolation between application tiers. Which design principle does this represent?',options:['Elasticity','Defense in depth using network segmentation','Operational Excellence — infrastructure as code','Cost Optimization — consolidate resources'],correct:1,explanation:'Defense in depth applies multiple layers of security controls. Network segmentation (separate VPC subnets per tier, security groups restricting inter-tier traffic, NACLs) limits lateral movement if one tier is compromised — a core security architecture principle in the AWS Well-Architected Security pillar.'},
{id:'ccp204',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company uses on-premises Microsoft Active Directory for authentication. They are deploying an internal web application on AWS and want employees to log in with their existing AD credentials without any re-enrollment. Which approach achieves this with the LEAST operational overhead?',options:['Recreate all AD users as IAM users manually','Deploy AD on EC2 and manually sync with on-premises','Use AWS Directory Service AD Connector to proxy authentication to on-premises AD','Create a separate Cognito user pool and import users via CSV'],correct:2,explanation:'AD Connector is a proxy that redirects authentication requests to your existing on-premises Active Directory without caching or syncing credentials in AWS. There is no replication to manage and no user re-enrollment — existing AD accounts work immediately for AWS service authentication.'},
{id:'ccp205',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company\'s AWS bill shows $8,000/month in data transfer OUT costs. Their application in us-east-1 serves users primarily in Europe and Asia-Pacific. What architectural change would MOST reduce these costs?',options:['Compress all responses with gzip at the application layer','Enable S3 Transfer Acceleration','Deploy CloudFront with edge locations in Europe and Asia-Pacific — users receive content from nearby edges, reducing origin data transfer out charges','Move the entire application to eu-west-1'],correct:2,explanation:'CloudFront\'s per-GB pricing for data delivered to end users is lower than direct EC2/S3 data transfer out rates. More importantly, cache hits serve from the edge with no origin transfer at all. Serving European and APAC users from regional edges rather than us-east-1 reduces both latency and egress costs significantly.'},
{id:'ccp206',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'An auditor requests evidence that no changes have been made to an S3 bucket\'s objects since they were stored — the data must be provably immutable. Which S3 feature provides this guarantee?',options:['S3 Versioning alone','S3 Object Lock in Compliance mode with a retention period','S3 Default Encryption','S3 Replication'],correct:1,explanation:'S3 Object Lock in Compliance mode prevents objects from being deleted or overwritten for the duration of the retention period by anyone, including the root user. This provides WORM (Write Once Read Many) protection suitable for regulatory and audit requirements. Governance mode can be bypassed by users with special permissions; Compliance mode cannot.'},
{id:'ccp207',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company runs a microservices application. Service A calls Service B synchronously, and when Service B is slow, Service A times out and fails too, cascading across the system. Which architectural pattern and AWS service combination addresses this?',options:['Add more EC2 instances to Service B','Use Amazon SQS to decouple Service A from Service B asynchronously, absorbing load spikes without cascading failures','Enable Multi-AZ on Service B\'s database','Add CloudWatch alarms for Service B latency'],correct:1,explanation:'Replacing the synchronous call with an SQS queue decouples the services. Service A enqueues messages and returns immediately; Service B processes at its own pace. Load spikes queue rather than cascade. This eliminates the timeout chain and is a core pattern for resilient microservice communication.'},
{id:'ccp208',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company wants to measure and minimize the environmental impact of their AWS workloads. Which Well-Architected pillar provides guidance on this, and which of the following is a recommended practice?',options:['Cost Optimization — use Reserved Instances to reduce spend','Sustainability — use AWS Graviton processors and serverless to reduce energy consumption per workload','Reliability — deploy to multiple regions to spread the load','Performance Efficiency — use larger instances to finish jobs faster'],correct:1,explanation:'The Sustainability pillar (added in 2021) focuses on reducing the environmental impact of cloud workloads. Key practices: use AWS Graviton (better performance-per-watt), serverless and managed services (no idle capacity), right-size instances, and use S3 Intelligent-Tiering to avoid storing rarely accessed data on energy-intensive storage.'},
{id:'ccp209',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company needs to run quarterly penetration tests against their own AWS infrastructure. What must they do before beginning?',options:['Nothing — penetration testing is always allowed on your own resources','Submit an AWS penetration testing request form and wait for approval for all service types','Review AWS\'s Penetration Testing policy — most services are permitted without prior approval, but certain activities (DoS simulation, DNS zone walking) remain prohibited','Purchase AWS Shield Advanced first'],correct:2,explanation:'AWS\'s current penetration testing policy permits customers to test their own resources for most services (EC2, RDS, CloudFront, API Gateway, Lambda, Lightsail, Elastic Beanstalk) without pre-approval. However, prohibited activities include DDoS simulation against AWS infrastructure, DNS zone walking, and port/protocol flooding. Always review the current AWS Customer Support Policy for Penetration Testing before starting.'},
{id:'ccp210',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company ingests clickstream data from 50,000 concurrent users in real time. They need to aggregate this data every 5 minutes and store results in a data warehouse for business intelligence queries. Which pipeline is MOST appropriate?',options:['Users → SQS → Lambda → RDS','Users → Kinesis Data Streams → Kinesis Data Firehose → Redshift','Users → S3 → Athena → QuickSight','Users → DynamoDB Streams → Lambda → S3'],correct:1,explanation:'Kinesis Data Streams ingests high-volume real-time streaming data. Kinesis Data Firehose buffers and delivers it to Redshift in micro-batches (configurable interval, e.g., every 5 minutes) without custom code. Redshift serves BI queries. This is the purpose-built AWS pattern for streaming-to-data-warehouse pipelines.'},
{id:'ccp211',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company has been running on AWS for 2 years. They have consistent EC2 usage but have never purchased Reserved Instances. AWS Cost Explorer\'s RI recommendations show potential savings of $4,200/month with a 12-month Standard RI commitment. The break-even is 7 months. What should the company consider before purchasing?',options:['Reserved Instances cannot be sold, so it\'s always too risky','Whether workloads will remain consistent for 12 months; if so, the $4,200/month savings makes this an excellent purchase. Unused RIs can be sold on the Reserved Instance Marketplace','Reserved Instances require upfront payment only — no flexibility','They should buy 3-year RIs instead for maximum savings regardless of workload stability'],correct:1,explanation:'The key consideration for Reserved Instances is workload stability over the commitment period. With break-even at 7 months and consistent 2-year history, a 12-month RI is financially sound. If needs change, Standard RIs can be sold on the RI Marketplace. 3-year commitments maximize savings but reduce flexibility — appropriate only for very stable, long-running workloads.'},
{id:'ccp212',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company wants to allow their mobile app users to upload photos directly to S3 without routing the upload through their application servers (to reduce server load and cost). How can they accomplish this securely?',options:['Make the S3 bucket public and let users upload directly','Generate a pre-signed S3 URL server-side with a short expiration time — the client uploads directly to S3 using that URL','Give all users IAM credentials with S3 write access','Use AWS Transfer Family SFTP endpoint'],correct:1,explanation:'A pre-signed URL is generated by the server using AWS credentials, granting the bearer temporary permission to perform a specific S3 operation (PUT) on a specific object for a limited time. The client uploads directly to S3 without the server handling the payload. The bucket remains private and the URL expires, preventing abuse.'},
{id:'ccp213',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company is evaluating two DR strategies. Strategy A (Pilot Light) keeps a minimal version of the environment running in AWS. Strategy B (Warm Standby) keeps a scaled-down but fully functional copy running. How do these compare in terms of RTO and cost?',options:['Pilot Light and Warm Standby have identical RTO and cost','Pilot Light has lower cost but higher RTO than Warm Standby; Warm Standby costs more but achieves lower RTO','Warm Standby is always cheaper because it uses fewer resources','Pilot Light achieves better RTO because it is simpler'],correct:1,explanation:'Pilot Light: only critical core components run (e.g., DB replication), other components must be provisioned/scaled during recovery → lower cost, higher RTO. Warm Standby: a fully functional but scaled-down version runs continuously → faster RTO (just scale up), but higher ongoing cost. The four DR strategies in order of cost/RTO: Backup & Restore → Pilot Light → Warm Standby → Multi-Site Active/Active.'},
{id:'ccp214',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company runs a multi-account AWS environment. A developer in Account A needs to access an S3 bucket in Account B. They should not need permanent IAM credentials. What is the RECOMMENDED approach?',options:['Create an IAM user in Account B and share the access keys with the developer','Make the S3 bucket in Account B public','Create a cross-account IAM Role in Account B with a trust policy allowing Account A, and have the developer assume the role via STS','Copy the data to Account A\'s S3 bucket weekly'],correct:2,explanation:'Cross-account IAM roles are the AWS-recommended pattern for cross-account access. The role in Account B trusts Account A\'s principal; the developer assumes the role via STS:AssumeRole, receiving temporary credentials scoped to the role\'s permissions. No permanent credentials are shared, and access can be revoked by modifying the role.'},
{id:'ccp215',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company runs thousands of IoT sensors that send temperature readings every second. They need to detect when any sensor exceeds 80°C within 10 seconds of the reading and trigger an alert. Which architecture achieves this with the LOWEST latency?',options:['Sensors → S3 → Athena query every minute','Sensors → AWS IoT Core → IoT Rules Engine → SNS alert (when temperature > 80)','Sensors → SQS → Lambda → DynamoDB → scheduled CloudWatch alarm','Sensors → Kinesis → Redshift → QuickSight dashboard'],correct:1,explanation:'AWS IoT Core ingests device data and the IoT Rules Engine evaluates SQL-like rules in real time against incoming messages. A rule like "SELECT * FROM sensors WHERE temperature > 80" triggers immediately on each message meeting the condition, invoking SNS for instant alerting — sub-second end-to-end, no batch processing.'},
{id:'ccp216',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company is building a new application and cannot yet predict traffic patterns. They want to avoid over-provisioning but also avoid performance issues. Which combination of services and pricing models best handles this uncertainty at launch?',options:['Reserved Instances for all components committed upfront','Provision for 10x expected peak using On-Demand to be safe','On-Demand instances with Auto Scaling (scales out/in based on actual demand) and review RI purchase opportunity after 1-2 months of data','Spot Instances for all components since they\'re cheapest'],correct:2,explanation:'For unpredictable new workloads, On-Demand + Auto Scaling is the right starting point: you pay only for what you use and auto-scale to match demand. After gathering 1-2 months of CloudWatch metrics, Cost Explorer\'s RI recommendations will be based on actual usage patterns, making any Reserved Instance commitment well-informed.'},
{id:'ccp217',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company needs to run a legacy Windows application that requires a specific version of Windows Server and has a license tied to the physical host (BYOL). They want to move this to AWS with the minimum licensing change. Which EC2 option is required?',options:['Spot Instance with Windows AMI','On-Demand Instance with Multi-AZ','Dedicated Host — provides a physical server you can use to bring your own host-based licenses','Reserved Instance with default tenancy'],correct:2,explanation:'Dedicated Hosts provide a physical EC2 server fully dedicated to your use, allowing you to use your existing per-socket or per-core server-bound Windows Server licenses (BYOL). Standard EC2 instances run on shared hardware with shared host identity, which doesn\'t satisfy host-based licensing requirements.'},
{id:'ccp218',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company\'s application must comply with a regulation requiring all customer data to remain within the European Union. Architects need to ensure no data replication outside EU regions occurs. Which AWS mechanisms enforce this?',options:['S3 Block Public Access prevents data from leaving the region','AWS automatically keeps data in the region where it is stored — no additional controls needed for region boundaries','Service Control Policies (SCPs) restricting resource creation to EU regions, plus explicit opt-in for any cross-region features (S3 CRR, RDS read replicas to non-EU regions)','AWS CloudTrail data residency mode'],correct:2,explanation:'AWS does not move data between regions without explicit customer action, but cross-region features (S3 CRR, RDS cross-region replicas, CloudFront) can be configured accidentally. SCPs denying resource creation outside approved EU regions (eu-west-1, eu-central-1, etc.) prevent developers from accidentally enabling cross-region replication to non-EU destinations.'},
{id:'ccp219',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company enables AWS Config and discovers that 15 EC2 security groups allow unrestricted SSH access (0.0.0.0/0 on port 22). They want this automatically fixed whenever it\'s detected. Which Config feature enables automatic remediation?',options:['AWS Config snapshot delivery to S3','Config Conformance Packs with manual review','AWS Config rule with automatic remediation action using Systems Manager Automation runbook','AWS Trusted Advisor with email notifications'],correct:2,explanation:'AWS Config rules evaluate resource configurations continuously. When a rule (like restricted-ssh) marks a resource as NON_COMPLIANT, a remediation action linked to an SSM Automation runbook can automatically fix it — in this case, removing the 0.0.0.0/0 port 22 ingress rule. This closes the loop from detect to remediate without human intervention.'},
{id:'ccp220',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company\'s application stores user-uploaded videos in S3. After upload, videos must be transcoded to multiple resolutions. Transcoding takes 5-30 minutes per video. On busy days, hundreds of videos are uploaded simultaneously. Which architecture handles this elastically without managing servers?',options:['EC2 instance polls S3 every minute for new uploads','S3 Event Notification → SQS queue → Auto Scaling group of EC2 workers pulling from the queue → processed output to S3','RDS trigger → EC2 transcoding cluster','CloudFront → Lambda → ffmpeg'],correct:1,explanation:'S3 events notify SQS immediately on upload. An Auto Scaling group of EC2 workers (or ECS tasks) polls the SQS queue — scaling out as the queue depth grows, scaling in when it drains. This handles burst without managing a fixed server pool and uses SQS as a durable buffer so no uploads are lost during scale-out.'},
{id:'ccp221',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company receives an unexpectedly high AWS bill. Cost Explorer shows a spike in data transfer costs from an EC2 instance in us-east-1. Upon investigation, the instance is sending large amounts of data to an external IP not belonging to the company. Which service would have alerted them to this anomaly EARLIEST?',options:['AWS Budgets cost alert (triggers after the spend occurs)','Amazon GuardDuty — detects unusual network traffic patterns indicative of data exfiltration','AWS Cost Anomaly Detection — detects the spend anomaly as it accumulates','AWS Trusted Advisor — weekly cost recommendations'],correct:1,explanation:'GuardDuty analyzes VPC Flow Logs and DNS logs in real time, with ML models specifically designed to detect data exfiltration patterns (unusual outbound traffic volume or destination). It would alert during the incident. Cost Anomaly Detection catches the financial impact after some spend accumulates. Budgets only alert on total cost thresholds, not behavior patterns.'},
{id:'ccp222',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company wants to migrate their on-premises MySQL database to AWS with minimal downtime — the database must remain online and accepting writes throughout the migration. Which service supports continuous replication from on-premises to RDS with near-zero downtime cutover?',options:['AWS Snowball Edge — ship the database files','AWS DataSync — sync file-based data','AWS Database Migration Service (DMS) with ongoing replication until cutover','AWS Backup — restore to RDS from a backup'],correct:2,explanation:'AWS DMS performs an initial full load of existing data, then uses Change Data Capture (CDC) to continuously replicate ongoing writes from the source to the target. The source database stays live. When replication lag reaches near-zero, you cutover with minimal downtime — often under a minute for the final DNS/connection switch.'},
{id:'ccp223',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company\'s architecture review identifies that all application data is stored in a single us-east-1 Availability Zone. The team argues that because they use RDS Multi-AZ, they are fully protected. What is the flaw in this reasoning?',options:['There is no flaw — RDS Multi-AZ protects against all failures','RDS Multi-AZ protects against AZ failure for the database, but the EC2 web tier, load balancer, and other components in a single AZ are still single points of failure','Multi-AZ doubles costs, which outweighs the reliability benefit','RDS Multi-AZ does not replicate data synchronously'],correct:1,explanation:'RDS Multi-AZ provides automatic failover for the database tier only. If the EC2 instances, load balancer, or other application components are in a single AZ, those remain SPOFs. True AZ-level fault tolerance requires ALL tiers to be distributed across multiple AZs — EC2 Auto Scaling across AZs, ALB spanning multiple AZs, and RDS Multi-AZ together.'},
{id:'ccp224',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company wants to enforce that all IAM users in their account must have MFA enabled before they can perform any actions beyond viewing their own MFA settings. How is this typically implemented?',options:['AWS automatically enforces MFA for all accounts','Create an IAM policy with a condition denying all actions except MFA management when MFA is not present, and attach it to all users or a group','Enable MFA in the AWS Console for each user manually','Purchase AWS Shield Advanced which includes MFA enforcement'],correct:1,explanation:'The standard pattern is an IAM policy with a condition: "Effect": "Deny" on all actions except iam:CreateVirtualMFADevice and iam:EnableMFADevice when the condition "Bool": {"aws:MultiFactorAuthPresent": "false"}. Attaching this to an "all users" group creates a self-service MFA enforcement gate without admin intervention per user.'},
{id:'ccp225',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A startup builds a REST API on API Gateway + Lambda. During load testing, they observe cold start latency of 800ms for the first request after a period of inactivity, impacting user experience. Which Lambda feature directly addresses this?',options:['Increase Lambda memory to maximum (10 GB)','Enable Lambda Provisioned Concurrency to keep a specified number of instances initialized and ready','Set a shorter Lambda timeout value','Switch to Lambda@Edge'],correct:1,explanation:'Lambda Provisioned Concurrency pre-initializes a specified number of execution environments so they are ready to respond instantly with no cold start delay. It eliminates the initialization time for those reserved instances. This has a cost (you pay for provisioned concurrency even when idle), so it\'s used for latency-sensitive endpoints.'},
{id:'ccp226',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'An organization uses AWS Organizations with 20 member accounts. They apply the following policy hierarchy: Root SCP allows all actions; OU-level SCP denies EC2 in ap-southeast-1; Account-level SCP denies S3 DeleteObject. An IAM admin in a member account tries to launch EC2 in ap-southeast-1. What happens?',options:['It succeeds — the root SCP allows all actions and overrides lower SCPs','It fails — the OU-level SCP denial takes effect; SCPs are evaluated as an intersection, and the explicit deny at the OU level cannot be overridden by the account','It depends on the IAM policy of the admin user','It succeeds only if the admin has AdministratorAccess'],correct:1,explanation:'SCP evaluation uses intersection logic: a principal must be allowed at EVERY level (Root → OU → Account) and by their IAM policy. An explicit Deny anywhere in the SCP hierarchy overrides all Allows regardless of the principal\'s IAM permissions. The OU-level denial of EC2 in ap-southeast-1 blocks the action even for account administrators.'},
{id:'ccp227',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company needs to run a containerized application that scales from zero to thousands of concurrent tasks during business hours and back to zero overnight. Minimizing cost during off-hours is critical. Which compute option is BEST?',options:['EC2 Reserved Instances running 24/7 for consistent availability','Amazon ECS with AWS Fargate — serverless containers that scale to zero when no tasks run','Amazon EKS with self-managed EC2 node groups','EC2 Auto Scaling with minimum capacity of 10 instances'],correct:1,explanation:'Fargate is serverless for containers — you pay only for vCPU and memory consumed while tasks are running. When scaled to zero (no running tasks), there is no charge. This is the optimal model for bursty, variable-duration workloads with long idle periods. EC2-based options always incur cost for the underlying instances even when idle.'},
{id:'ccp228',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company is planning a migration and categorizes each application into one of the 6 Rs. Their custom-built CRM is costly to maintain, and a SaaS alternative exists. Which migration strategy applies?',options:['Rehost — move the CRM to EC2','Replatform — move to RDS','Repurchase — replace with a SaaS CRM (e.g., Salesforce)','Re-architect — rewrite as microservices'],correct:2,explanation:'Repurchase (also called "drop and shop") means replacing an existing application with a commercial off-the-shelf or SaaS product. Moving from a custom CRM to Salesforce is the canonical example. It eliminates maintenance burden immediately at the cost of migration effort and potential feature differences.'},
{id:'ccp229',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company hosts a public API on API Gateway. They begin receiving requests that appear to be from automated bots scraping their data at 10,000 requests per second from a small set of IP addresses. Which TWO controls should they implement immediately? (Select the best combined answer.)',options:['Enable CloudTrail logging and review logs manually','Attach an AWS WAF Web ACL to API Gateway with an IP-based rate limit rule and block the known offending IPs in an IP set rule','Increase API Gateway throttling limits to handle the load','Enable AWS Shield Standard — it handles all bot traffic automatically'],correct:1,explanation:'AWS WAF on API Gateway provides: (1) IP set rules to block known malicious IPs immediately; (2) rate-based rules to automatically block any IP exceeding a request threshold (e.g., 1,000/5 min). These take effect in minutes. Shield Standard protects against DDoS volumetric attacks but is not designed for application-layer bot scraping patterns.'},
{id:'ccp230',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A financial services company needs to maintain a complete, tamper-proof audit log of every transaction processed by their application. The log must be cryptographically verifiable — it must be provable that no record was altered or deleted after the fact. Which AWS service is PURPOSE-BUILT for this requirement?',options:['Amazon CloudWatch Logs with S3 export','Amazon S3 with versioning enabled','Amazon QLDB (Quantum Ledger Database) — provides an immutable, cryptographically verifiable transaction log','AWS CloudTrail with log file validation'],correct:2,explanation:'Amazon QLDB is a fully managed ledger database with a built-in immutable journal. Every change is cryptographically chained (SHA-256 hash of each block includes the hash of the previous block), so any alteration to historical records is mathematically detectable. It\'s purpose-built for financial transactions, supply chain, and any application requiring a verifiable audit trail.'},
];
